def _generate_run_id():
    """Generate a run_id: run_YYYYMMDD_HHMMSS_<8hex>."""
    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    return f"run_{ts}_{secrets.token_hex(4)}"


def _env_flag_enabled(name: str) -> bool:
    """Return True if an environment flag is set to a truthy value."""
    value = os.environ.get(name, "").strip().lower()
    return value in {"1", "true", "yes", "on"}


def _sha256_bytes(raw: bytes) -> str:
    return hashlib.sha256(raw).hexdigest()


def _pixmap_sha256_png(pix: QPixmap) -> str:
    if pix.isNull():
        return ""
    payload = QByteArray()
    buffer = QBuffer(payload)
    if not buffer.open(QIODevice.OpenModeFlag.WriteOnly):
        return ""
    try:
        if not pix.save(buffer, "PNG"):
            return ""
    finally:
        buffer.close()
    return _sha256_bytes(bytes(payload))


class _GuidedRoiDiscoveryWorker(QObject):
    succeeded = Signal(object)
    failed = Signal(str)
    diagnostic = Signal(object)

    def __init__(
        self,
        snapshot: dict[str, object],
        spec_builder,
        *,
        start_monotonic: float,
        gui_thread_id: int,
    ):
        super().__init__()
        self._snapshot = dict(snapshot)
        self._spec_builder = spec_builder
        self._start_monotonic = float(start_monotonic)
        self._gui_thread_id = int(gui_thread_id)

    def _diag(self, label: str, **fields) -> None:
        if not GUIDED_DISCOVERY_DIAGNOSTICS:
            return
        self.diagnostic.emit(
            {
                "elapsed_sec": time.monotonic() - self._start_monotonic,
                "thread_id": threading.get_ident(),
                "gui_thread_id": self._gui_thread_id,
                "label": label,
                "fields": fields,
            }
        )

    def run(self) -> None:
        self._diag("worker_run_entered")
        try:
            build_started = time.monotonic()
            self._diag("worker_build_spec_start")
            spec = self._spec_builder(self._snapshot)
            self._diag(
                "worker_build_spec_end",
                duration_sec=time.monotonic() - build_started,
            )
            started = time.monotonic()
            self._diag("run_discovery_start")
            result = spec.run_discovery()
            self._diag(
                "run_discovery_end",
                duration_sec=time.monotonic() - started,
                sessions=len(result.get("sessions", [])),
                rois=len(result.get("rois", [])),
                resolved_format=result.get("resolved_format", ""),
            )
            self._diag("worker_emit_success")
            self.succeeded.emit(result)
        except Exception as exc:
            self._diag(
                "worker_failure",
                exception_type=type(exc).__name__,
                message=str(exc),
            )
            self.failed.emit(f"{type(exc).__name__}: {exc}")


class _GuidedCorrectionPreviewWorker(QObject):
    """Run one already-snapshotted local correction preview off the GUI thread."""

    succeeded = Signal(object)
    failed = Signal(object)

    def __init__(
        self,
        args: tuple,
        kwargs: dict[str, object],
        report_inputs: dict[str, object],
    ):
        super().__init__()
        self._args = tuple(args)
        self._kwargs = dict(kwargs)
        self._report_inputs = dict(report_inputs)

    def run(self) -> None:
        try:
            result = run_guided_local_correction_preview(
                *self._args,
                **self._kwargs,
            )
        except Exception as exc:
            self.failed.emit(
                {
                    "stage": "preview_computation_failed",
                    "message": f"{type(exc).__name__}: {exc}",
                    "preview_output_dir": str(
                        self._report_inputs.get("preview_output_dir") or ""
                    ),
                }
            )
            return
        try:
            generate_guided_correction_preview_reports(
                result,
                report_inputs=self._report_inputs,
            )
        except Exception as exc:
            self.failed.emit(
                {
                    "stage": "preview_report_failed",
                    "message": f"{type(exc).__name__}: {exc}",
                    "preview_output_dir": str(
                        self._report_inputs.get("preview_output_dir") or ""
                    ),
                }
            )
            return
        self.succeeded.emit(result)


class _GuidedCompletedReviewLoadWorker(QObject):
    """Read one compact completed-run overview without retaining GUI state."""

    succeeded = Signal(object)
    failed = Signal(str)

    def __init__(self, run_dir: str):
        super().__init__()
        self._run_dir = str(run_dir)

    def run(self) -> None:
        try:
            overview = load_completed_review_overview(self._run_dir)
        except Exception as exc:
            self.failed.emit(f"{type(exc).__name__}: {exc}")
            return
        self.succeeded.emit(dict(overview))


class _GuidedRunExecutionWorker(QObject):
    """Runs the existing synchronous Guided backend execution seam off the GUI thread.

    `request` (the immutable retained `GuidedStartupTransactionRequest`) and
    `runner` (the optional low-level subprocess-runner override) are both
    captured on the GUI thread before the worker starts and handed in as
    plain constructor arguments. This worker holds no reference to
    `MainWindow` and calls only the module-level `execute_guided_backend_run`
    function; it must never call a MainWindow method or read a MainWindow
    attribute, since it runs on a separate thread.
    """

    succeeded = Signal(object)
    failed = Signal(str)

    def __init__(self, request, runner):
        super().__init__()
        self._request = request
        self._runner = runner

    def run(self) -> None:
        from photometry_pipeline.guided_backend_execution import (
            execute_guided_backend_run,
        )

        try:
            result = execute_guided_backend_run(
                request=self._request, runner=self._runner
            )
        except Exception as exc:
            self.failed.emit(f"{type(exc).__name__}: {exc}")
            return
        self.succeeded.emit(result)


@dataclasses.dataclass(frozen=True)
class _GuidedNpmRunWorkerFailure:
    """Internal-only marker for a pre-reconciliation NPM run-worker failure.

    Never displayed directly and never persisted to disk. `stage` selects
    which scientist-facing text branch the GUI thread applies; `category`
    is the stable backend category (if any), used only to look up a safe
    mapped detail sentence -- the raw backend issue message is never
    carried across this boundary.
    """

    stage: str
    category: str | None = None


class _GuidedNpmRunWorker(QObject):
    """Builds the prelaunch claim, launches the NPM worker, and reconciles
    it -- entirely off the GUI thread.

    Holds only the plain, already-captured validation context/outcome/
    revision values; it must never call a MainWindow method, read a
    MainWindow/widget attribute, or infer current GUI values after
    starting, since it runs on a separate thread. It calls only the
    existing module-level `build_guided_npm_worker_prelaunch_claim_from_
    validation`, `launch_guided_npm_worker_runtime`,
    `reconcile_guided_npm_worker_runtime`, and
    `reconcile_guided_npm_post_launch_runtime` functions -- it never
    replicates their internal chains.
    """

    launched = Signal(object, bool)
    succeeded = Signal(object)
    failed = Signal(object)

    def __init__(
        self,
        *,
        validation_context,
        validation_outcome,
        current_gui_revision: int,
    ):
        super().__init__()
        self._validation_context = validation_context
        self._validation_outcome = validation_outcome
        self._current_gui_revision = current_gui_revision

    def run(self) -> None:
        from photometry_pipeline.guided_npm_run_launch_builder import (
            build_guided_npm_worker_prelaunch_claim_from_validation,
        )
        from photometry_pipeline.guided_npm_worker_launch import (
            GuidedNpmLaunchedWorkerRuntime,
            GuidedNpmPostLaunchRuntime,
            GuidedNpmWorkerLaunchCancelled,
            GuidedNpmWorkerLaunchFailure,
            launch_guided_npm_worker_runtime,
        )
        from photometry_pipeline.guided_npm_worker_reconciliation import (
            reconcile_guided_npm_post_launch_runtime,
            reconcile_guided_npm_worker_runtime,
        )

        try:
            build_result = build_guided_npm_worker_prelaunch_claim_from_validation(
                validation_context=self._validation_context,
                validation_outcome=self._validation_outcome,
                current_gui_revision=self._current_gui_revision,
            )
        except Exception:
            self.failed.emit(_GuidedNpmRunWorkerFailure(stage="unexpected_error"))
            return
        if build_result is None or not build_result.ok:
            self.failed.emit(
                _GuidedNpmRunWorkerFailure(
                    stage="build_failed",
                    category=getattr(build_result, "status", None),
                )
            )
            return

        try:
            launch_result = launch_guided_npm_worker_runtime(
                build_result.prelaunch_claim,
                current_application_build_identity=(
                    build_result.application_build_identity
                ),
            )
        except Exception:
            self.failed.emit(_GuidedNpmRunWorkerFailure(stage="unexpected_error"))
            return

        if isinstance(launch_result, GuidedNpmWorkerLaunchCancelled):
            self.failed.emit(_GuidedNpmRunWorkerFailure(stage="launch_cancelled"))
            return

        if isinstance(launch_result, GuidedNpmWorkerLaunchFailure):
            blocking_issues = (
                getattr(launch_result, "blocking_issues", None) or ()
            )
            category = (
                blocking_issues[0].category if blocking_issues else None
            )
            self.failed.emit(
                _GuidedNpmRunWorkerFailure(
                    stage="launch_failed", category=category
                )
            )
            return

        if not isinstance(
            launch_result,
            (GuidedNpmLaunchedWorkerRuntime, GuidedNpmPostLaunchRuntime),
        ):
            # Any other/unexpected outcome must never be treated as
            # started or completed.
            self.failed.emit(_GuidedNpmRunWorkerFailure(stage="unexpected_error"))
            return

        is_post_launch = isinstance(launch_result, GuidedNpmPostLaunchRuntime)
        self.launched.emit(launch_result, is_post_launch)

        try:
            if is_post_launch:
                result = reconcile_guided_npm_post_launch_runtime(launch_result)
            else:
                result = reconcile_guided_npm_worker_runtime(launch_result)
        except Exception:
            self.failed.emit(_GuidedNpmRunWorkerFailure(stage="unexpected_error"))
            return
        self.succeeded.emit(result)


def _open_folder(path: str) -> None:
    """Cross-platform open a folder in the file manager."""
    if sys.platform == "win32":
        os.startfile(path)
    elif sys.platform == "darwin":
        _subprocess.run(["open", path], check=False)
    else:
        _subprocess.run(["xdg-open", path], check=False)


def _open_file(path: str) -> None:
    """Cross-platform open a file with the default associated app."""
    if sys.platform == "win32":
        os.startfile(path)
    elif sys.platform == "darwin":
        _subprocess.run(["open", path], check=False)
    else:
        _subprocess.run(["xdg-open", path], check=False)


def parse_and_validate_isosbestic_knobs(
    window_sec_str: str,
    step_sec_str: str,
    min_valid_windows_val: int,
    r_low_str: str,
    r_high_str: str,
    g_min_str: str,
    min_samples_val: int,
    defaults: dict,
) -> tuple[dict | None, str | None]:
    """
    Parses and validates isosbestic correction knobs for the active rolling-fit engine.
    Returns (dict_of_overrides, None) if valid.
    Returns (None, error_message) if invalid.

    Legacy dynamic-fit knobs are retained in emitted overrides for compatibility
    but are sourced from defaults and treated as inactive in the active engine.
    """
    ws_text = window_sec_str.strip()
    try:
        ws = float(ws_text if ws_text else defaults["window_sec"])
        if ws <= 0:
            return None, "Regression Window must be > 0."
    except ValueError:
        return None, "Regression Window must be a number."
    if min_samples_val < 1:
        return None, "Min Samples per Window must be >= 1."

    # Legacy/inactive under rolling fit; preserve defaults for backward compatibility.
    try:
        ss = float(defaults["step_sec"])
        r_low = float(defaults["r_low"])
        r_high = float(defaults["r_high"])
        g_min = float(defaults["g_min"])
        min_valid_windows = int(defaults["min_valid_windows"])
    except (KeyError, TypeError, ValueError):
        cfg0 = Config()
        ss = float(cfg0.step_sec)
        r_low = float(cfg0.r_low)
        r_high = float(cfg0.r_high)
        g_min = float(cfg0.g_min)
        min_valid_windows = int(cfg0.min_valid_windows)

    overrides = {
        "window_sec": ws,
        "step_sec": ss,
        "min_valid_windows": min_valid_windows,
        "r_low": r_low,
        "r_high": r_high,
        "g_min": g_min,
        "min_samples_per_window": min_samples_val,
    }
    return overrides, None


def parse_and_validate_robust_event_reject_knobs(
    max_iters_val: int,
    residual_z_thresh_val: float,
    local_var_window_sec_val: float,
    local_var_ratio_thresh_enabled: bool,
    local_var_ratio_thresh_val: float,
    min_keep_fraction_val: float,
    defaults: dict,
) -> tuple[dict | None, str | None]:
    """
    Parse and validate robust_global_event_reject controls.
    """
    max_iters = int(max_iters_val)
    if max_iters < 1:
        return None, "Max iterations must be >= 1."

    residual_z = float(residual_z_thresh_val)
    if residual_z <= 0.0:
        return None, "Residual z-threshold must be > 0."

    local_window = float(local_var_window_sec_val)
    if local_window <= 0.0:
        return None, "Local variance window must be > 0."

    min_keep_fraction = float(min_keep_fraction_val)
    if not (0.0 < min_keep_fraction <= 1.0):
        return None, "Minimum keep fraction must be in (0, 1]."

    ratio_thresh = None
    if bool(local_var_ratio_thresh_enabled):
        ratio_thresh = float(local_var_ratio_thresh_val)
        if ratio_thresh <= 0.0:
            return None, "Local variance ratio threshold must be > 0 when enabled."

    overrides = {
        "robust_event_reject_max_iters": max_iters,
        "robust_event_reject_residual_z_thresh": residual_z,
        "robust_event_reject_local_var_window_sec": local_window,
        "robust_event_reject_local_var_ratio_thresh": ratio_thresh,
        "robust_event_reject_min_keep_fraction": min_keep_fraction,
    }
    return overrides, None


def parse_and_validate_adaptive_event_gated_knobs(
    residual_z_thresh_val: float,
    local_var_window_sec_val: float,
    local_var_ratio_thresh_enabled: bool,
    local_var_ratio_thresh_val: float,
    smooth_window_sec_val: float,
    min_trust_fraction_val: float,
    freeze_interp_method_text: str,
    defaults: dict,
) -> tuple[dict | None, str | None]:
    """
    Parse and validate adaptive_event_gated_regression controls.
    """
    residual_z = float(residual_z_thresh_val)
    if residual_z <= 0.0:
        return None, "Residual z-threshold must be > 0."

    local_window = float(local_var_window_sec_val)
    if local_window <= 0.0:
        return None, "Local variance window must be > 0."

    smooth_window = float(smooth_window_sec_val)
    if smooth_window <= 0.0:
        return None, "Smooth window must be > 0."

    min_trust = float(min_trust_fraction_val)
    if not (0.0 < min_trust <= 1.0):
        return None, "Minimum trust fraction must be in (0, 1]."

    freeze_interp_method = str(freeze_interp_method_text or "").strip() or "linear_hold"
    if freeze_interp_method not in {"linear_hold"}:
        return None, "Freeze interpolation method must be 'linear_hold'."

    ratio_thresh = None
    if bool(local_var_ratio_thresh_enabled):
        ratio_thresh = float(local_var_ratio_thresh_val)
        if ratio_thresh <= 0.0:
            return None, "Local variance ratio threshold must be > 0 when enabled."

    overrides = {
        "adaptive_event_gate_residual_z_thresh": residual_z,
        "adaptive_event_gate_local_var_window_sec": local_window,
        "adaptive_event_gate_local_var_ratio_thresh": ratio_thresh,
        "adaptive_event_gate_smooth_window_sec": smooth_window,
        "adaptive_event_gate_min_trust_fraction": min_trust,
        "adaptive_event_gate_freeze_interp_method": freeze_interp_method,
    }
    return overrides, None


def normalize_dynamic_fit_slope_constraint(mode_raw: str) -> str:
    mode = str(mode_raw or "").strip().lower()
    if mode in _DYNAMIC_FIT_SLOPE_CONSTRAINT_LABELS:
        return mode
    return "unconstrained"


def dynamic_fit_slope_constraint_label(mode_raw: str) -> str:
    mode = normalize_dynamic_fit_slope_constraint(mode_raw)
    return _DYNAMIC_FIT_SLOPE_CONSTRAINT_LABELS.get(
        mode, _DYNAMIC_FIT_SLOPE_CONSTRAINT_LABELS["unconstrained"]
    )


def parse_and_validate_dynamic_fit_slope_constraint_knobs(
    constraint_text: str,
    min_slope_val: float,
) -> tuple[dict | None, str | None]:
    constraint = normalize_dynamic_fit_slope_constraint(constraint_text)
    try:
        min_slope = float(min_slope_val)
    except (TypeError, ValueError):
        return None, "Minimum allowed slope must be a finite number."
    if not math.isfinite(min_slope):
        return None, "Minimum allowed slope must be a finite number."
    if constraint == "nonnegative" and min_slope < 0.0:
        return None, "Minimum allowed slope must be >= 0 when nonnegative reference coupling is required."
    return {
        "dynamic_fit_slope_constraint": constraint,
        "dynamic_fit_min_slope": min_slope,
    }, None


def is_isosbestic_active(mode_text: str) -> bool:
    """Return True if the mode implies phasic analysis will run."""
    return mode_text in ("both", "phasic")


def get_isosbestic_overrides_if_active(mode_text: str, parsed_overrides: dict) -> dict:
    """Return the overrides only if the mode implies phasic analysis will run."""
    if is_isosbestic_active(mode_text):
        return parsed_overrides
    return {}


def compute_isosbestic_overrides_user_changed(parsed: dict, defaults: dict) -> dict:
    """
    Returns only the key/value pairs in parsed that differ from the defaults.
    """
    changed = {}
    for k, v in parsed.items():
        if k in defaults and v != defaults[k]:
            changed[k] = v
    return changed

