def format_robust_event_reject_settings_summary(
    max_iters: int,
    residual_z_thresh: float,
    local_var_window_sec: float,
    local_var_ratio_thresh: float | None,
    min_keep_fraction: float,
) -> str:
    ratio_text = (
        "disabled"
        if local_var_ratio_thresh is None
        else f"{float(local_var_ratio_thresh):.4g}"
    )
    return (
        "Robust event-reject settings: "
        f"max_iters={int(max_iters)}, "
        f"residual_z={float(residual_z_thresh):.4g}, "
        f"local_var_window_s={float(local_var_window_sec):.4g}, "
        f"local_var_ratio={ratio_text}, "
        f"min_keep={float(min_keep_fraction):.4g}"
    )


def format_adaptive_event_gated_settings_summary(
    residual_z_thresh: float,
    local_var_window_sec: float,
    local_var_ratio_thresh: float | None,
    smooth_window_sec: float,
    min_trust_fraction: float,
    freeze_interp_method: str,
) -> str:
    ratio_text = (
        "disabled"
        if local_var_ratio_thresh is None
        else f"{float(local_var_ratio_thresh):.4g}"
    )
    return (
        "Adaptive event-gated settings: "
        f"residual_z={float(residual_z_thresh):.4g}, "
        f"local_var_window_s={float(local_var_window_sec):.4g}, "
        f"local_var_ratio={ratio_text}, "
        f"smooth_window_s={float(smooth_window_sec):.4g}, "
        f"min_trust={float(min_trust_fraction):.4g}, "
        f"freeze_interp={str(freeze_interp_method or 'linear_hold')}"
    )


def get_retune_peak_pre_filters() -> list[str]:
    return list(_RETUNE_PEAK_PRE_FILTER_OPTIONS)


def normalize_retune_peak_pre_filter(mode_raw: str) -> str:
    mode = str(mode_raw or "none").strip().lower()
    if mode == "none":
        return "none"
    if mode in {"smooth", "lowpass"}:
        return "smooth"
    return "none"


def map_retune_peak_pre_filter_to_run_setting(mode_raw: str) -> str:
    # Main run settings keep legacy config semantics for full-pipeline compatibility.
    mode = normalize_retune_peak_pre_filter(mode_raw)
    return "lowpass" if mode == "smooth" else "none"

_cached_percentile_reqs = {}

def baseline_method_requires_percentile(method_str: str) -> bool:
    """
    Returns True if the given baseline method requires a percentile parameter.
    Determined deterministically from the Config schema behavior, without heuristics.
    """
    global _cached_percentile_reqs
    if method_str in _cached_percentile_reqs:
        return _cached_percentile_reqs[method_str]

    allowed = get_allowed_baseline_methods_from_config()
    if method_str not in allowed:
        _cached_percentile_reqs[method_str] = False
        return False

    try:
        # Construct two configs differing only in baseline_percentile
        cfg1 = Config(baseline_method=method_str, baseline_percentile=10.0)
        cfg2 = Config(baseline_method=method_str, baseline_percentile=50.0)
        
        # If changing the input percentile changes the effective percentile, it is required.
        req = (cfg1.baseline_percentile != cfg2.baseline_percentile)
        _cached_percentile_reqs[method_str] = req
        return req
    except Exception:
        # Fallback if instantiation fails for some reason
        _cached_percentile_reqs[method_str] = False
        return False

def parse_and_validate_preproc_baseline_knobs(
    lowpass_hz_str: str,
    baseline_method_text: str,
    baseline_percentile_str: str,
    f0_min_value_str: str,
    defaults: dict,
) -> tuple[dict | None, str | None]:
    """
    Parses and validates the preprocessing and baseline advanced knobs.
    Returns (dict_of_overrides, None) if valid.
    Returns (None, error_message) if invalid.
    """
    try:
        lp_val = lowpass_hz_str.strip()
        lowpass_hz = float(lp_val if lp_val else defaults["lowpass_hz"])
        if lowpass_hz <= 0:
            return None, "Lowpass Filter (Hz) must be > 0."
    except ValueError:
        return None, "Lowpass Filter (Hz) must be a number."

    method = baseline_method_text.strip()
    allowed_methods = get_allowed_baseline_methods_from_config()
    if method not in allowed_methods:
        return None, "Invalid Baseline Method."

    try:
        f0_val = f0_min_value_str.strip()
        f0_min = float(f0_val if f0_val else defaults["f0_min_value"])
        if f0_min < 0:
            return None, "F0 Min Value must be >= 0."
    except ValueError:
        return None, "F0 Min Value must be a number."

    overrides = {
        "lowpass_hz": lowpass_hz,
        "baseline_method": method,
        "f0_min_value": f0_min,
    }

    if baseline_method_requires_percentile(method):
        try:
            pct_val = baseline_percentile_str.strip()
            # Careful not to accidentally validate if we shouldn't have been parsing
            pct = float(pct_val if pct_val else defaults["baseline_percentile"])
            if not (0 <= pct <= 100):
                return None, "Baseline Percentile must be between 0 and 100."
            overrides["baseline_percentile"] = pct
        except ValueError:
            return None, "Baseline Percentile must be a number."

    return overrides, None

def peak_threshold_method_requires_k(method_str: str) -> bool:
    """K-threshold applies to std/mad-style methods only."""
    return method_str in {"mean_std", "median_mad"}

def peak_threshold_method_requires_percentile(method_str: str) -> bool:
    """Percentile threshold applies only to percentile method."""
    return method_str == "percentile"

def peak_threshold_method_requires_abs(method_str: str) -> bool:
    """Absolute threshold applies only to absolute method."""
    return method_str == "absolute"


# Scientist-facing Step 5 Default-settings status language. Loaded, valid
# defaults are already effective for ROIs marked Default; the button is a
# convenience for accepting edits, not a separate authorization gate.
GUIDED_DEFAULT_SETTINGS_NOT_CONFIRMED = (
    "These starting Default settings are ready for ROIs marked Default."
)
GUIDED_DEFAULT_SETTINGS_READY = "Default settings are ready."
GUIDED_DEFAULT_SETTINGS_CONFIRM_BEFORE_CONTINUING = (
    "Default settings need attention before continuing."
)
GUIDED_DEFAULT_SETTINGS_CHANGED_AFTER_CONFIRMATION = (
    "Default settings changed. Confirm them again before continuing."
)
GUIDED_DEFAULT_SETTINGS_NEED_ATTENTION = (
    "Default settings need attention before continuing."
)
GUIDED_DEFAULT_SETTINGS_LOAD_FAILURE_ADVICE = (
    "Check the selected data and recording settings, then try again."
)
GUIDED_DEFAULT_SETTINGS_COULD_NOT_LOAD = (
    "The starting Default settings could not be loaded. "
    + GUIDED_DEFAULT_SETTINGS_LOAD_FAILURE_ADVICE
)
GUIDED_DEFAULT_SETTINGS_FILE_NOT_FOUND = (
    "The starting settings file was not found. "
    + GUIDED_DEFAULT_SETTINGS_LOAD_FAILURE_ADVICE
)
GUIDED_DEFAULT_SETTINGS_FILE_UNREADABLE = (
    "The starting settings file could not be read. "
    + GUIDED_DEFAULT_SETTINGS_LOAD_FAILURE_ADVICE
)


def sanitize_guided_default_settings_load_failure(fallback_reason: object) -> str:
    """Map a raw Default-settings loader diagnostic to a stable, scientist-facing
    message.

    resolve_feature_event_defaults' fallback_reason is a shared loader
    diagnostic that can contain file paths, the word "config", parser names and
    raw exception text. None of that may reach the visible Step 5 labels, so
    this returns only one of a small known set of plain-language messages and
    never echoes any part of the raw reason. Callers keep the raw reason in
    _guided_new_analysis_feature_event_profile_errors for internal diagnostics.
    """
    reason = str(fallback_reason or "").strip().lower()
    if not reason:
        return GUIDED_DEFAULT_SETTINGS_COULD_NOT_LOAD
    if "does not exist" in reason or "not found" in reason:
        return GUIDED_DEFAULT_SETTINGS_FILE_NOT_FOUND
    if "unable to load" in reason or "could not" in reason or "parse" in reason:
        return GUIDED_DEFAULT_SETTINGS_FILE_UNREADABLE
    return GUIDED_DEFAULT_SETTINGS_COULD_NOT_LOAD


def normalize_feature_settings_for_active_threshold_method(config_fields: dict) -> dict:
    """Return a copy of config_fields with threshold fields that are inactive
    for the selected peak_threshold_method removed.

    A full/effective feature-detection config can carry a dormant value for a
    threshold field that the selected method does not use (e.g.
    peak_threshold_abs=0.0 while the method is mean_std). validate_feature_event_config_fields
    intentionally validates every present numeric field regardless of the
    active method, so a dormant peak_threshold_abs=0.0 would otherwise fail as
    "peak_threshold_abs must be > 0" even though absolute thresholding is not
    in use. Dropping inactive threshold fields here mirrors what
    parse_and_validate_event_feature_knobs already does for the Default editor,
    so Default and Custom-ROI previews validate identically. The active
    threshold field for the selected method is always kept, so required-field
    checks downstream still pass.
    """
    normalized = dict(config_fields or {})
    method = str(normalized.get("peak_threshold_method", ""))
    if not peak_threshold_method_requires_k(method):
        normalized.pop("peak_threshold_k", None)
    if not peak_threshold_method_requires_percentile(method):
        normalized.pop("peak_threshold_percentile", None)
    if not peak_threshold_method_requires_abs(method):
        normalized.pop("peak_threshold_abs", None)
    return normalized


def validate_representative_index_preview_compatibility(
    representative_session_index: int | None,
    preview_first_n: int | None,
) -> str | None:
    """Validate representative-session selection against preview truncation."""
    if representative_session_index is None or preview_first_n is None:
        return None
    if representative_session_index >= preview_first_n:
        return (
            f"Representative Session index {representative_session_index} is out of range for "
            f"Preview first N={preview_first_n}. Choose (auto) or a lower session index."
        )
    return None


def _event_feature_semantic_error_to_gui_message(issue: str) -> str:
    """Map shared semantic validation issues to existing GUI-style messages."""

    if "invalid event_signal" in issue:
        return "Invalid Event Signal."
    if "invalid signal_excursion_polarity" in issue:
        return "Invalid Signal Excursion Polarity."
    if "invalid peak_threshold_method" in issue:
        return "Invalid Peak Threshold Method."
    if "peak_threshold_k must be numeric" in issue:
        return "Peak Threshold K must be a number."
    if "peak_threshold_k must be >" in issue:
        return "Peak Threshold K must be > 0."
    if "peak_threshold_percentile must be numeric" in issue:
        return "Peak Threshold Percentile must be a number."
    if "peak_threshold_percentile" in issue:
        return "Peak Threshold Percentile must be between 0 and 100."
    if "peak_threshold_abs must be numeric" in issue:
        return "Peak Threshold Absolute must be a number."
    if "peak_threshold_abs" in issue:
        return "Peak Threshold Absolute must be > 0."
    if "peak_min_distance_sec must be numeric" in issue:
        return "Peak Min Distance (sec) must be a number."
    if "peak_min_distance_sec" in issue:
        return "Peak Min Distance (sec) must be >= 0."
    if "peak_min_prominence_k must be numeric" in issue:
        return "Peak Min Prominence K must be a number."
    if "peak_min_prominence_k" in issue:
        return "Peak Min Prominence K must be >= 0."
    if "peak_min_width_sec must be numeric" in issue:
        return "Peak Min Width (s) must be a number."
    if "peak_min_width_sec" in issue:
        return "Peak Min Width (s) must be >= 0."
    if "invalid peak_pre_filter" in issue:
        return "Invalid Peak Pre-Filter."
    if "invalid event_auc_baseline" in issue:
        return "Invalid Event AUC Baseline."
    return issue


def parse_and_validate_event_feature_knobs(
    event_signal_text: str,
    peak_method_text: str,
    peak_k_str: str,
    peak_pct_str: str,
    peak_abs_str: str,
    peak_dist_str: str,
    event_auc_text: str,
    defaults: dict,
    peak_pre_filter_text: str | None = None,
    peak_prominence_k_str: str | None = None,
    peak_width_sec_str: str | None = None,
    signal_excursion_polarity_text: str | None = None,
) -> tuple[dict | None, str | None]:
    """
    Parses and validates the event + feature advanced knobs.
    Returns (dict_of_overrides, None) if valid.
    Returns (None, error_message) if invalid.
    """
    event_sig_method = event_signal_text.strip()
    allowed_event_signals = get_allowed_event_signals_from_config()
    if event_sig_method not in allowed_event_signals:
        return None, "Invalid Event Signal."

    include_polarity = (
        signal_excursion_polarity_text is not None
        or "signal_excursion_polarity" in defaults
    )
    signal_excursion_polarity = "positive"
    if include_polarity:
        if signal_excursion_polarity_text is None:
            signal_excursion_polarity_raw = str(
                defaults.get("signal_excursion_polarity", "positive")
            ).strip().lower()
        else:
            signal_excursion_polarity_raw = str(signal_excursion_polarity_text).strip().lower()
        allowed_polarities = get_allowed_signal_excursion_polarities_from_config()
        if signal_excursion_polarity_raw not in allowed_polarities:
            return None, "Invalid Signal Excursion Polarity."
        signal_excursion_polarity = normalize_signal_excursion_polarity(
            signal_excursion_polarity_raw
        )

    peak_method = peak_method_text.strip()
    allowed_peak_methods = get_allowed_peak_threshold_methods_from_config()
    if peak_method not in allowed_peak_methods:
        return None, "Invalid Peak Threshold Method."
        
    auc_baseline = event_auc_text.strip()
    allowed_auc_baselines = get_allowed_event_auc_baselines_from_config()
    if auc_baseline not in allowed_auc_baselines:
        return None, "Invalid Event AUC Baseline."

    if peak_pre_filter_text is None:
        peak_pre_filter = str(defaults.get("peak_pre_filter", "none"))
    else:
        peak_pre_filter = peak_pre_filter_text.strip()
    allowed_peak_pre_filters = get_allowed_peak_pre_filters_from_config()
    if peak_pre_filter not in allowed_peak_pre_filters:
        return None, "Invalid Peak Pre-Filter."

    try:
        dist_val = peak_dist_str.strip()
        peak_dist = float(dist_val if dist_val else defaults["peak_min_distance_sec"])
        if peak_dist < 0:
            return None, "Peak Min Distance (sec) must be >= 0."
    except ValueError:
        return None, "Peak Min Distance (sec) must be a number."

    try:
        prom_val = peak_prominence_k_str.strip() if peak_prominence_k_str is not None else ""
        peak_prominence_k = float(prom_val if prom_val else defaults.get("peak_min_prominence_k", 0.0))
        if peak_prominence_k < 0:
            return None, "Peak Min Prominence K must be >= 0."
    except ValueError:
        return None, "Peak Min Prominence K must be a number."

    try:
        width_val = peak_width_sec_str.strip() if peak_width_sec_str is not None else ""
        peak_width_sec = float(width_val if width_val else defaults.get("peak_min_width_sec", 0.0))
        if peak_width_sec < 0:
            return None, "Peak Min Width (s) must be >= 0."
    except ValueError:
        return None, "Peak Min Width (s) must be a number."

    overrides = {
        "event_signal": event_sig_method,
        "peak_threshold_method": peak_method,
        "peak_min_distance_sec": peak_dist,
        "peak_min_prominence_k": peak_prominence_k,
        "peak_min_width_sec": peak_width_sec,
        "peak_pre_filter": peak_pre_filter,
        "event_auc_baseline": auc_baseline,
    }
    if include_polarity:
        overrides["signal_excursion_polarity"] = signal_excursion_polarity

    if peak_threshold_method_requires_k(peak_method):
        try:
            k_val = peak_k_str.strip()
            k = float(k_val if k_val else defaults["peak_threshold_k"])
            if k <= 0:
                return None, "Peak Threshold K must be > 0."
            overrides["peak_threshold_k"] = k
        except ValueError:
            return None, "Peak Threshold K must be a number."
            
    if peak_threshold_method_requires_percentile(peak_method):
        try:
            pct_val = peak_pct_str.strip()
            pct = float(pct_val if pct_val else defaults["peak_threshold_percentile"])
            if not (0 <= pct <= 100):
                return None, "Peak Threshold Percentile must be between 0 and 100."
            overrides["peak_threshold_percentile"] = pct
        except ValueError:
            return None, "Peak Threshold Percentile must be a number."
            
    if peak_threshold_method_requires_abs(peak_method):
        try:
            abs_val = peak_abs_str.strip()
            abs_v = float(abs_val if abs_val else defaults["peak_threshold_abs"])
            if abs_v <= 0:
                return None, "Peak Threshold Absolute must be > 0."
            overrides["peak_threshold_abs"] = abs_v
        except ValueError:
            return None, "Peak Threshold Absolute must be a number."

    semantic_errors = validate_feature_event_config_fields(overrides)
    if semantic_errors:
        return None, _event_feature_semantic_error_to_gui_message(semantic_errors[0])

    return overrides, None



def compute_overrides_user_changed(parsed: dict, defaults: dict) -> dict:
    """
    Generic helper: returns only key/value pairs in parsed that differ from defaults.
    """
    changed = {}
    for k, v in parsed.items():
        if k in defaults and v != defaults[k]:
            changed[k] = v
    return changed


class _GuidedRoiFeatureEventDialog(QDialog):
    """Customize feature detection settings for one ROI.

    Uses the same field set and validator as the shared default settings
    editor. Applying here only affects this one ROI; the default settings
    and every other ROI are unaffected until this dialog's Apply button is
    used, and nothing here is saved unless Apply succeeds.
    """

    _HARD_DEFAULTS = {
        "event_signal": "dff",
        "signal_excursion_polarity": "positive",
        "peak_threshold_method": "mean_std",
        "peak_threshold_k": 2.5,
        "peak_threshold_percentile": 95.0,
        "peak_threshold_abs": 0.0,
        "peak_min_distance_sec": 1.0,
        "peak_min_prominence_k": 2.0,
        "peak_min_width_sec": 0.3,
        "peak_pre_filter": "none",
        "event_auc_baseline": "zero",
    }

    def __init__(self, roi_id: str, seed_values: dict, parent=None):
        super().__init__(parent)
        self._roi_id = roi_id
        self._defaults = {**self._HARD_DEFAULTS, **(seed_values or {})}
        self._result_values: dict | None = None
        self.setWindowTitle(f"Customize feature detection for {roi_id}")

        layout = QVBoxLayout(self)
        note = QLabel(
            f"You are editing feature detection for {roi_id} only. These "
            "fields start from the settings currently in effect for this "
            f"ROI. What you apply here changes {roi_id} alone — the Default "
            "settings and every other ROI stay the same."
        )
        note.setObjectName("guidedRoiFeatureEventDialogNote")
        note.setWordWrap(True)
        layout.addWidget(note)

        form = QFormLayout()
        form.setSpacing(6)

        self._signal_combo = QComboBox()
        self._signal_combo.addItems(get_allowed_event_signals_from_config())
        self._signal_combo.setCurrentText(str(self._defaults["event_signal"]))
        form.addRow("Event signal:", self._signal_combo)

        self._polarity_combo = QComboBox()
        self._polarity_combo.addItems(get_allowed_signal_excursion_polarities_from_config())
        self._polarity_combo.setCurrentText(str(self._defaults["signal_excursion_polarity"]))
        form.addRow("Signal excursion polarity:", self._polarity_combo)

        self._peak_method_combo = QComboBox()
        self._peak_method_combo.addItems(get_allowed_peak_threshold_methods_from_config())
        self._peak_method_combo.setCurrentText(str(self._defaults["peak_threshold_method"]))
        form.addRow("Peak threshold method:", self._peak_method_combo)

        self._peak_k_edit = QLineEdit(str(self._defaults["peak_threshold_k"]))
        form.addRow("Peak threshold k:", self._peak_k_edit)

        self._peak_pct_edit = QLineEdit(str(self._defaults["peak_threshold_percentile"]))
        form.addRow("Peak threshold percentile:", self._peak_pct_edit)

        self._peak_abs_edit = QLineEdit(str(self._defaults["peak_threshold_abs"]))
        form.addRow("Peak threshold absolute:", self._peak_abs_edit)

        self._peak_distance_edit = QLineEdit(str(self._defaults["peak_min_distance_sec"]))
        form.addRow("Peak min distance (sec):", self._peak_distance_edit)

        self._peak_prominence_edit = QLineEdit(str(self._defaults["peak_min_prominence_k"]))
        form.addRow("Peak min prominence k:", self._peak_prominence_edit)

        self._peak_width_edit = QLineEdit(str(self._defaults["peak_min_width_sec"]))
        form.addRow("Peak min width (sec):", self._peak_width_edit)

        self._pre_filter_combo = QComboBox()
        self._pre_filter_combo.addItems(get_allowed_peak_pre_filters_from_config())
        self._pre_filter_combo.setCurrentText(str(self._defaults["peak_pre_filter"]))
        form.addRow("Peak pre-filter:", self._pre_filter_combo)

        self._auc_baseline_combo = QComboBox()
        self._auc_baseline_combo.addItems(get_allowed_event_auc_baselines_from_config())
        self._auc_baseline_combo.setCurrentText(str(self._defaults["event_auc_baseline"]))
        form.addRow("Event AUC baseline:", self._auc_baseline_combo)

        layout.addLayout(form)

        self._error_label = QLabel("")
        self._error_label.setObjectName("guidedRoiFeatureEventDialogError")
        self._error_label.setWordWrap(True)
        self._error_label.setVisible(False)
        layout.addWidget(self._error_label)

        button_row = QHBoxLayout()
        apply_btn = QPushButton(f"Apply to {roi_id}")
        apply_btn.setObjectName("guidedRoiFeatureEventDialogApplyButton")
        apply_btn.clicked.connect(self._on_apply)
        button_row.addWidget(apply_btn)
        cancel_btn = QPushButton("Cancel")
        cancel_btn.setObjectName("guidedRoiFeatureEventDialogCancelButton")
        cancel_btn.clicked.connect(self.reject)
        button_row.addWidget(cancel_btn)
        layout.addLayout(button_row)

    def _current_values(self) -> tuple[dict | None, str | None]:
        return parse_and_validate_event_feature_knobs(
            self._signal_combo.currentText(),
            self._peak_method_combo.currentText(),
            self._peak_k_edit.text(),
            self._peak_pct_edit.text(),
            self._peak_abs_edit.text(),
            self._peak_distance_edit.text(),
            self._auc_baseline_combo.currentText(),
            defaults=self._defaults,
            peak_pre_filter_text=self._pre_filter_combo.currentText(),
            peak_prominence_k_str=self._peak_prominence_edit.text(),
            peak_width_sec_str=self._peak_width_edit.text(),
            signal_excursion_polarity_text=self._polarity_combo.currentText(),
        )

    def _on_apply(self) -> None:
        values, error = self._current_values()
        if error:
            self._error_label.setText(error)
            self._error_label.setVisible(True)
            return
        self._result_values = values
        self.accept()

    def result_values(self) -> dict | None:
        return self._result_values


_ClickableImageLabel = InteractiveImageLabel


