    def _connect_guided_setup_sync(self) -> None:
        """Connect Guided setup controls to the existing Full Control setup widgets."""
        if getattr(self, "_guided_setup_sync_connected", False):
            return
        required = (
            "_guided_input_dir_edit",
            "_guided_output_dir_edit",
            "_guided_format_combo",
            "_guided_acquisition_mode_combo",
            "_guided_sessions_per_hour_edit",
            "_guided_session_duration_edit",
            "_guided_continuous_window_sec_spin",
            "_guided_allow_partial_final_window_cb",
            "_guided_exclude_incomplete_final_rwd_chunk_cb",
        )
        if not all(hasattr(self, name) for name in required):
            return

        self._guided_setup_syncing = False

        self._guided_input_dir_edit.textChanged.connect(
            lambda text: self._sync_line_edit_value(self._input_dir, text)
        )
        self._guided_input_dir_edit.textChanged.connect(
            lambda _text: self._refresh_guided_navigation_state()
        )
        self._guided_output_dir_edit.textChanged.connect(
            lambda text: self._sync_line_edit_value(self._output_dir, text)
        )
        self._guided_output_dir_edit.textChanged.connect(
            lambda _text: self._refresh_guided_navigation_state()
        )
        self._guided_output_dir_edit.textChanged.connect(
            lambda _text: self._invalidate_guided_backend_validation(
                "output destination changed"
            )
        )
        self._guided_format_combo.currentIndexChanged.connect(
            self._on_guided_format_changed
        )
        self._guided_format_combo.currentIndexChanged.connect(
            self._clear_guided_missing_session_approvals_for_source_change
        )
        self._guided_acquisition_mode_combo.currentIndexChanged.connect(
            lambda _idx: self._sync_combo_data_value(
                self._acquisition_mode_combo,
                self._guided_acquisition_mode_combo.currentData(),
            )
        )
        self._guided_acquisition_mode_combo.currentIndexChanged.connect(
            lambda _idx: self._refresh_guided_navigation_state()
        )
        self._guided_acquisition_mode_combo.currentIndexChanged.connect(
            self._clear_guided_missing_session_approvals_for_source_change
        )
        self._guided_sessions_per_hour_edit.textChanged.connect(
            lambda text: self._sync_line_edit_value(self._sph_edit, text)
        )
        self._guided_sessions_per_hour_edit.textEdited.connect(
            self._on_guided_recording_timing_user_edit
        )
        self._guided_sessions_per_hour_edit.textChanged.connect(
            lambda _text: self._refresh_guided_navigation_state()
        )
        self._guided_session_duration_edit.textChanged.connect(
            lambda text: self._sync_line_edit_value(self._duration_edit, text)
        )
        self._guided_session_duration_edit.textEdited.connect(
            self._on_guided_recording_timing_user_edit
        )
        self._guided_session_duration_edit.textChanged.connect(
            lambda _text: self._refresh_guided_navigation_state()
        )
        self._guided_continuous_window_sec_spin.valueChanged.connect(
            lambda value: self._sync_spin_value(self._continuous_window_sec_spin, value)
        )
        self._guided_continuous_window_sec_spin.valueChanged.connect(
            lambda _value: self._refresh_guided_navigation_state()
        )
        self._guided_allow_partial_final_window_cb.stateChanged.connect(
            lambda _state: self._sync_checkbox_value(
                self._allow_partial_final_window_cb,
                self._guided_allow_partial_final_window_cb.isChecked(),
            )
        )
        self._guided_exclude_incomplete_final_rwd_chunk_cb.stateChanged.connect(
            lambda _state: self._sync_checkbox_value(
                self._exclude_incomplete_final_rwd_chunk_cb,
                self._guided_exclude_incomplete_final_rwd_chunk_cb.isChecked(),
            )
        )
        self._guided_input_dir_edit.textChanged.connect(
            lambda _text: self._invalidate_guided_backend_validation(
                "input source changed"
            )
        )
        self._guided_input_dir_edit.textChanged.connect(
            self._clear_guided_missing_session_approvals_for_source_change
        )
        self._guided_acquisition_mode_combo.currentIndexChanged.connect(
            lambda _idx: self._invalidate_guided_backend_validation(
                "acquisition mode changed"
            )
        )
        self._guided_sessions_per_hour_edit.textChanged.connect(
            lambda _text: self._invalidate_guided_backend_validation(
                "sessions per hour changed"
            )
        )
        self._guided_session_duration_edit.textChanged.connect(
            lambda _text: self._invalidate_guided_backend_validation(
                "session duration changed"
            )
        )
        self._guided_continuous_window_sec_spin.valueChanged.connect(
            lambda _value: self._invalidate_guided_backend_validation(
                "acquisition window changed"
            )
        )
        self._guided_allow_partial_final_window_cb.stateChanged.connect(
            lambda _state: self._invalidate_guided_backend_validation(
                "partial final window policy changed"
            )
        )
        self._guided_exclude_incomplete_final_rwd_chunk_cb.stateChanged.connect(
            lambda _state: self._invalidate_guided_backend_validation(
                "incomplete final RWD policy changed"
            )
        )

        self._input_dir.textChanged.connect(lambda _text: self._sync_guided_setup_from_full())
        self._output_dir.textChanged.connect(lambda _text: self._sync_guided_setup_from_full())
        self._format_combo.currentIndexChanged.connect(lambda _idx: self._sync_guided_setup_from_full())
        self._acquisition_mode_combo.currentIndexChanged.connect(
            lambda _idx: self._sync_guided_setup_from_full()
        )
        self._sph_edit.textChanged.connect(lambda _text: self._sync_guided_setup_from_full())
        self._duration_edit.textChanged.connect(lambda _text: self._sync_guided_setup_from_full())
        self._continuous_window_sec_spin.valueChanged.connect(
            lambda _value: self._sync_guided_setup_from_full()
        )
        self._allow_partial_final_window_cb.stateChanged.connect(
            lambda _state: self._sync_guided_setup_from_full()
        )
        self._exclude_incomplete_final_rwd_chunk_cb.stateChanged.connect(
            lambda _state: self._sync_guided_setup_from_full()
        )
        self._guided_setup_sync_connected = True

    def _guided_setup_summary_state(self) -> dict[str, object]:
        """Collect run-spec/config-relevant setup state without writing artifacts."""
        selected_rois: list[str] = []
        all_rois: list[str] = []
        if getattr(self, "_discovery_cache", None) is not None:
            for idx in range(self._roi_list.count()):
                item = self._roi_list.item(idx)
                if item is None:
                    continue
                all_rois.append(item.text())
                if item.checkState() == Qt.Checked:
                    selected_rois.append(item.text())
        resolved_format = ""
        if getattr(self, "_discovery_cache", None) is not None:
            resolved_format = str(self._discovery_cache.get("resolved_format", "") or "")
        return {
            "input_dir": self._input_dir.text().strip(),
            "output_dir": self._output_dir.text().strip(),
            "format": self._format_combo.currentText(),
            "resolved_format": resolved_format,
            "acquisition_mode": self._selected_acquisition_mode(),
            "sessions_per_hour": self._sph_edit.text().strip(),
            "session_duration_s": self._duration_edit.text().strip(),
            "continuous_window_sec": float(self._continuous_window_sec_spin.value()),
            "continuous_step_sec": float(self._continuous_window_sec_spin.value()),
            "allow_partial_final_window": bool(self._allow_partial_final_window_cb.isChecked()),
            "exclude_incomplete_final_rwd_chunk": bool(
                self._exclude_incomplete_final_rwd_chunk_cb.isChecked()
            ),
            "selected_roi_count": len(selected_rois),
            "total_roi_count": len(all_rois),
            "selected_rois": selected_rois,
            "reference_correction_method": self._selected_dynamic_fit_mode(),
            "reference_correction_label": dynamic_fit_mode_label(self._selected_dynamic_fit_mode()),
            "guided_correction_intent": getattr(self, "_guided_correction_intent", "") or "not selected",
        }

    def _refresh_guided_setup_summary(
        self,
        *,
        lightweight: bool = False,
    ) -> None:
        """Refresh Guided display panels that depend on current setup state.

        4J16k28: the raw-state "Current setup summary" debug panel was
        removed from the visible shell (Review Plan's scientist-facing
        summaries and technical-details toggle cover that need). This
        method is kept -- and still named for its historical role -- as
        the shared cascade-refresh hook that several setup-state mutation
        handlers call; `_guided_setup_summary_state()` itself also remains,
        since it backs the Guided/Full Control setup-equivalence checks and
        the Correction Approach page's own "Completed-run details" panel.
        """
        if lightweight:
            return
        if hasattr(self, "_guided_diagnostics_status_label"):
            self._refresh_guided_diagnostics_panel()
        if hasattr(self, "_guided_start_status_label"):
            self._refresh_guided_start_panel()
        if hasattr(self, "_guided_mode_banner_label"):
            self._refresh_guided_mode_display()

    def _set_guided_workflow_mode(self, mode: str) -> None:
        if mode not in {"start", "new_analysis", "open_results"}:
            mode = "start"
        self._guided_workflow_mode = mode
        self._refresh_guided_mode_display()
        self._refresh_guided_start_panel()
        if hasattr(self, "_guided_diagnostics_status_label"):
            self._refresh_guided_diagnostics_panel()
        self._refresh_guided_confirm_strategy_panel()
        self._refresh_guided_navigation_state()

    def _guided_select_data_ready_to_continue(self) -> bool:
        if getattr(self, "_guided_workflow_mode", "start") != "new_analysis":
            return False
        if not self._guided_input_dir_edit.text().strip():
            return False
        if not self._guided_output_dir_edit.text().strip():
            return False
        if getattr(self, "_discovery_cache", None) is None:
            return False
        return bool(self._guided_selected_roi_ids()[1])

    def _guided_recording_structure_ready_to_continue(self) -> bool:
        ready, _reason = self._guided_recording_structure_readiness()
        return ready

    def _guided_recording_structure_readiness(
        self,
    ) -> tuple[bool, str]:
        if getattr(self, "_guided_workflow_mode", "start") != "new_analysis":
            return (
                False,
                "Complete required recording structure fields to continue.",
            )
        mode = str(
            self._guided_acquisition_mode_combo.currentData() or ""
        ).strip()
        if mode == "continuous":
            if self._guided_continuous_window_sec_spin.value() <= 0:
                return (
                    False,
                    "Continuous analysis window must be greater than 0 seconds.",
                )
            return True, "Recording structure is ready."
        if mode != "intermittent":
            return (
                False,
                "Select an acquisition mode to continue.",
            )
        resolved_format = str(
            (getattr(self, "_discovery_cache", None) or {}).get(
                "resolved_format",
                self._guided_format_combo.currentText(),
            )
        ).strip().lower()
        sessions_text = self._guided_sessions_per_hour_edit.text().strip()
        duration_text = self._guided_session_duration_edit.text().strip()
        if not sessions_text or not duration_text:
            return (
                False,
                "Enter sessions per hour and session duration to continue.",
            )
        try:
            sessions_per_hour = int(sessions_text)
        except ValueError:
            return (
                False,
                "Sessions per hour must be a positive whole number.",
            )
        if sessions_per_hour <= 0:
            return (
                False,
                "Sessions per hour must be a positive whole number.",
            )
        try:
            session_duration = float(duration_text)
        except ValueError:
            return (
                False,
                "Session duration must be greater than 0 seconds.",
            )
        if session_duration <= 0:
            return (
                False,
                "Session duration must be greater than 0 seconds.",
            )
        if sessions_per_hour * session_duration > 3600:
            return (
                False,
                "Session timing is impossible: sessions per hour × session "
                "duration cannot exceed 3600 seconds.",
            )
        return True, "Recording structure is ready."

    def _reach_guided_step(self, step_name: str) -> None:
        index = self._guided_step_index(step_name)
        self._guided_reached_step_indices.add(index)
        self._refresh_guided_navigation_state()

    def _refresh_guided_navigation_state(self) -> None:
        if not hasattr(self, "_guided_workflow_stepper"):
            return
        reached = getattr(self, "_guided_reached_step_indices", {0})
        for index in range(self._guided_workflow_stepper.count()):
            item = self._guided_workflow_stepper.item(index)
            flags = item.flags()
            if index in reached:
                flags |= Qt.ItemIsEnabled | Qt.ItemIsSelectable
            else:
                flags &= ~Qt.ItemIsEnabled
                flags &= ~Qt.ItemIsSelectable
            item.setFlags(flags)
        select_ready = bool(
            hasattr(self, "_guided_select_data_continue_btn")
            and self._guided_select_data_ready_to_continue()
        )
        if hasattr(self, "_guided_select_data_continue_btn"):
            self._guided_select_data_continue_btn.setEnabled(select_ready)
            self._guided_select_data_continue_status.setText(
                "Data selection is ready."
                if select_ready
                else "Select data and include at least one ROI to continue."
            )
        recording_ready = False
        recording_reason = (
            "Complete required recording structure fields to continue."
        )
        if hasattr(self, "_guided_recording_continue_btn"):
            recording_ready, recording_reason = (
                self._guided_recording_structure_readiness()
            )
        if hasattr(self, "_guided_recording_continue_btn"):
            self._guided_recording_continue_btn.setEnabled(recording_ready)
            self._guided_recording_continue_status.setText(
                recording_reason
            )
        self._refresh_guided_correction_continue_state()
        self._refresh_guided_feature_detection_continue_state()

    def _on_guided_continue_to_recording_structure(self) -> None:
        if not self._guided_select_data_ready_to_continue():
            self._refresh_guided_navigation_state()
            return
        self._reach_guided_step("Recording structure")
        self._guided_workflow_stepper.setCurrentRow(
            self._guided_step_index("Recording structure")
        )

    def _on_guided_continue_to_correction_approach(self) -> None:
        if not self._guided_recording_structure_ready_to_continue():
            self._refresh_guided_navigation_state()
            return
        self._reach_guided_step("Correction approach")
        self._guided_workflow_stepper.setCurrentRow(
            self._guided_step_index("Correction approach")
        )

    def _guided_feature_detection_readiness(self) -> tuple[bool, str]:
        status = str(
            getattr(
                self,
                "_guided_new_analysis_feature_event_profile_status",
                "missing",
            )
            or "missing"
        )
        errors = list(
            getattr(
                self,
                "_guided_new_analysis_feature_event_profile_errors",
                (),
            )
            or ()
        )
        stale_reasons = list(
            getattr(
                self,
                "_guided_new_analysis_feature_event_profile_stale_reasons",
                (),
            )
            or ()
        )
        profile = getattr(
            self, "_guided_new_analysis_feature_event_profile", None
        )
        if status in {"applied", "default_initialized"}:
            if not isinstance(profile, dict) or not profile or errors or stale_reasons:
                return False, GUIDED_DEFAULT_SETTINGS_NEED_ATTENTION
            included = self._guided_included_roi_ids_for_feature_detection()
            if not included:
                return False, "Include at least one ROI before continuing."
            for roi_id in included:
                effective = (
                    self._guided_effective_feature_event_config_fields_for_roi(
                        roi_id
                    )
                )
                validation_errors = validate_feature_event_config_fields(
                    self._guided_active_feature_event_config_fields(effective)
                )
                if validation_errors:
                    return (
                        False,
                        f"Choose valid feature settings for {roi_id} before "
                        "continuing.",
                    )
            overrides = getattr(
                self, "_guided_per_roi_feature_event_overrides", {}
            ) or {}
            uses_default = any(roi_id not in overrides for roi_id in included)
            if (
                uses_default
                and getattr(self, "_guided_feature_event_editor_dirty", False)
            ):
                return (
                    True,
                    "The saved Default settings and all Custom settings are "
                    "ready. Edits still shown in the Default form will not "
                    "be used unless you select ‘Use these as Default settings’.",
                )
            return True, "Feature detection settings are ready for every included ROI."
        if status == "stale":
            return (
                False,
                GUIDED_DEFAULT_SETTINGS_CHANGED_AFTER_CONFIRMATION,
            )
        if status == "unavailable":
            # errors[0] is the raw loader diagnostic (paths, "config", parser
            # and exception text). Never surface it here -- map it to a stable
            # plain-language message instead.
            return (
                False,
                sanitize_guided_default_settings_load_failure(
                    errors[0] if errors else ""
                ),
            )
        if status == "invalid":
            # These are field-level validation messages (e.g. "peak_threshold_abs
            # must be > 0"), which are scientist-actionable and safe to show.
            detail = str(errors[0]).strip() if errors else ""
            return (
                False,
                GUIDED_DEFAULT_SETTINGS_NEED_ATTENTION
                + (f" {detail}" if detail else ""),
            )
        return (
            False,
            GUIDED_DEFAULT_SETTINGS_CONFIRM_BEFORE_CONTINUING,
        )

    def _refresh_guided_feature_detection_continue_state(self) -> None:
        button = getattr(
            self, "_guided_feature_detection_continue_btn", None
        )
        status_label = getattr(
            self, "_guided_feature_detection_continue_status", None
        )
        if button is None or status_label is None:
            return
        ready, message = self._guided_feature_detection_readiness()
        button.setEnabled(ready)
        status_label.setText(message)
        self._refresh_guided_feature_detection_summary()
        self._refresh_guided_feature_detection_preview_panel()
        self._refresh_guided_per_roi_feature_event_table()

    def _guided_feature_detection_summary_text(self, plan=None) -> str:
        status = (
            str(plan.feature_event_profile_status or "missing")
            if plan is not None
            else str(
                getattr(
                    self,
                    "_guided_new_analysis_feature_event_profile_status",
                    "missing",
                )
                or "missing"
            )
        )
        explicitly_applied = (
            bool(plan.feature_event_explicitly_applied)
            if plan is not None
            else status == "applied"
        )
        if status == "applied" and explicitly_applied:
            display = "Confirmed"
            action = GUIDED_DEFAULT_SETTINGS_READY
        elif status == "default_initialized":
            display = "Ready"
            action = "Starting Default settings are ready."
        else:
            display = "Needs attention"
            action = GUIDED_DEFAULT_SETTINGS_NEED_ATTENTION
        threshold_method = (
            self._guided_feature_event_peak_method_combo.currentText()
        )
        if threshold_method == "percentile":
            threshold_value = self._guided_feature_event_peak_pct_edit.text()
        elif threshold_method == "absolute":
            threshold_value = self._guided_feature_event_peak_abs_edit.text()
        else:
            threshold_value = self._guided_feature_event_peak_k_edit.text()
        return (
            f"Status: {display}\n"
            f"Event signal: {self._guided_feature_event_signal_combo.currentText()}\n"
            f"Polarity: {self._guided_feature_event_polarity_combo.currentText()}\n"
            f"Threshold: {threshold_method} ({threshold_value})\n"
            "Minimum distance: "
            f"{self._guided_feature_event_peak_distance_edit.text()} s; "
            "minimum prominence: "
            f"{self._guided_feature_event_peak_prominence_edit.text()}; "
            f"minimum width: {self._guided_feature_event_peak_width_edit.text()} s\n"
            f"AUC baseline: {self._guided_feature_event_auc_baseline_combo.currentText()}\n"
            f"{action}"
        )

    def _refresh_guided_feature_detection_summary(self) -> None:
        label = getattr(
            self, "_guided_feature_detection_summary_label", None
        )
        if label is not None:
            label.setText(self._guided_feature_detection_summary_text())

    def _on_guided_continue_to_review_plan(self) -> None:
        ready, message = self._guided_feature_detection_readiness()
        self._guided_feature_detection_continue_btn.setEnabled(ready)
        self._guided_feature_detection_continue_status.setText(message)
        if not ready:
            return
        self._reach_guided_step("Draft plan")
        self._guided_workflow_stepper.setCurrentRow(
            self._guided_step_index("Draft plan")
        )

    def _on_guided_continue_to_run(self) -> None:
        from photometry_pipeline.guided_new_analysis_plan import (
            evaluate_guided_new_analysis_execution_subset_readiness,
            evaluate_new_analysis_plan_readiness,
        )

        plan = self._build_guided_new_analysis_draft_plan()
        readiness = evaluate_new_analysis_plan_readiness(plan)
        subset_readiness = evaluate_guided_new_analysis_execution_subset_readiness(
            plan
        )
        ready = bool(
            readiness.plan_complete_for_handoff
            and subset_readiness.first_subset_executable
        )
        button = getattr(self, "_guided_review_go_to_run_btn", None)
        if button is not None:
            button.setEnabled(ready)
        if not ready:
            return
        self._reach_guided_step("Run")
        self._guided_workflow_stepper.setCurrentRow(
            self._guided_step_index("Run")
        )

    def _display_path(self, path: str, *, max_chars: int = 60) -> str:
        text = str(path or "").strip()
        if len(text) <= max_chars:
            return text
        return "..." + text[-(max_chars - 3):]

    def _make_guided_widget_shrinkable(self, widget: QWidget) -> None:
        widget.setSizePolicy(QSizePolicy.Ignored, widget.sizePolicy().verticalPolicy())
        if hasattr(widget, "setMinimumWidth"):
            widget.setMinimumWidth(0)

    def _refresh_guided_mode_display(self) -> None:
        mode = getattr(self, "_guided_workflow_mode", "start")
        input_dir = self._input_dir.text().strip() if hasattr(self, "_input_dir") else ""
        run_dir = os.path.realpath((self._current_run_dir or "").strip())
        has_loaded_results = (
            hasattr(self, "_report_viewer")
            and bool(self._report_viewer.has_loaded_results())
            and bool(run_dir)
        )
        if hasattr(self, "_guided_mode_banner_label"):
            if mode == "new_analysis":
                if input_dir:
                    folder_name = (
                        os.path.basename(os.path.normpath(input_dir))
                        or input_dir
                    )
                    full_text = f"New analysis using: {input_dir}"
                    text = f"New analysis using: {folder_name}"
                else:
                    full_text = "New analysis"
                    text = "New analysis"
            elif mode == "open_results":
                full_text = (
                    "Mode: Open Results - "
                    f"Completed run: {run_dir if has_loaded_results else 'none'} - "
                    "Raw input setup unchanged"
                )
                text = (
                    "Mode: Open Results - "
                    f"Completed run: {self._display_path(run_dir) if has_loaded_results else 'none'} - "
                    "Raw input setup unchanged"
                )
            else:
                full_text = "Mode: choose a starting path - set up a new analysis or open completed results."
                text = (
                    "Mode: choose a starting path - set up a new analysis or open completed results."
                )
            self._guided_mode_banner_label.setText(text)
            self._guided_mode_banner_label.setToolTip(full_text)
        skipped = mode == "open_results"
        for banner in getattr(self, "_guided_skipped_setup_banners", {}).values():
            banner.setVisible(bool(skipped))
        for controls in getattr(self, "_guided_raw_setup_controls", {}).values():
            controls.setVisible(not skipped)
        for panel in getattr(self, "_guided_open_results_mode_panels", {}).values():
            panel.setVisible(skipped)
        for panel in getattr(self, "_guided_new_analysis_mode_panels", {}).values():
            panel.setVisible(not skipped)
        dataset_group = getattr(self, "_guided_dataset_contract_group", None)
        if dataset_group is not None:
            dataset_group.setVisible(mode == "new_analysis")
        self._refresh_guided_imported_plan_review_visibility()
        if hasattr(self, "_guided_confirm_context_label"):
            self._refresh_guided_confirm_strategy_panel()
        self._refresh_guided_draft_run_plan_preview()

    def _refresh_guided_imported_plan_review_visibility(self) -> None:
        """Imported plan review is completed-run tooling; hide it in
        new-analysis mode unless the user has already opened a plan."""
        group = getattr(self, "_guided_imported_plan_review_group", None)
        if group is None:
            return
        mode = getattr(self, "_guided_workflow_mode", "start")
        has_candidate = (
            getattr(self, "_guided_imported_plan_candidate", None) is not None
        )
        group.setVisible(mode != "new_analysis" or has_candidate)

    def _refresh_guided_start_panel(self) -> None:
        if not hasattr(self, "_guided_start_status_label"):
            return
        input_dir = self._input_dir.text().strip() if hasattr(self, "_input_dir") else ""
        run_dir = os.path.realpath((self._current_run_dir or "").strip())
        has_loaded_results = (
            hasattr(self, "_report_viewer")
            and bool(self._report_viewer.has_loaded_results())
            and bool(run_dir)
        )
        lines = []
        mode = getattr(self, "_guided_workflow_mode", "start")
        if mode == "new_analysis":
            lines.append("Current mode: Set up a new analysis")
        elif mode == "open_results":
            lines.append("Current mode: Open results from a completed run")
        else:
            lines.append("Current mode: choose a starting path")
        if has_loaded_results:
            lines.extend(["Completed run loaded:", run_dir])
        else:
            lines.append("No completed run loaded.")
        if input_dir:
            lines.extend(["Input data selected:", input_dir])
        else:
            lines.append("No input data selected.")
        self._guided_start_status_label.setText("\n".join(lines))
        if hasattr(self, "_guided_start_setup_status_label"):
            input_display = self._display_path(input_dir) if input_dir else ""
            if mode == "new_analysis":
                # This is the folder actively in use for the in-progress
                # setup, not merely a carried-over value from a prior
                # session -- safe to present as the current setting.
                setup_status_text = f"Input folder: {input_display or 'not selected'}"
            elif input_dir:
                # Nothing has been configured for a new analysis yet; this
                # value is only carried over from the last session, so it
                # must not read as an already-configured analysis.
                setup_status_text = f"Last input folder used: {input_display}"
            else:
                setup_status_text = "Input folder: not selected"
            self._guided_start_setup_status_label.setText(setup_status_text)
            self._guided_start_setup_status_label.setToolTip(input_dir)
            self._guided_start_setup_btn.setText(
                "Continue setup" if getattr(self, "_guided_workflow_mode", "start") == "new_analysis" else "Set up new analysis"
            )
        if hasattr(self, "_guided_start_open_status_label"):
            run_display = self._display_path(run_dir) if has_loaded_results else "none"
            self._guided_start_open_status_label.setText(
                f"Completed run: {run_display}"
            )
            self._guided_start_open_status_label.setToolTip(run_dir if has_loaded_results else "")

    def _on_guided_stepper_row_changed(self, idx: int) -> None:
        if idx < 0 or idx >= len(GUIDED_WORKFLOW_STEPS):
            return
        if getattr(self, "_guided_workflow_mode", "start") == "start":
            step_name = GUIDED_WORKFLOW_STEPS[idx]
            if step_name in {
                "Select data",
                "Recording structure",
                "Correction approach",
                "Draft plan",
                "Run",
            }:
                self._set_guided_workflow_mode("new_analysis")
        self._guided_workflow_stack.setCurrentIndex(idx)
        self._refresh_guided_mode_display()

    def _on_guided_start_setup_new_analysis(self) -> None:
        starting_fresh = (
            getattr(self, "_guided_workflow_mode", "start") != "new_analysis"
        )
        self._set_guided_workflow_mode("new_analysis")
        if starting_fresh and hasattr(self, "_guided_format_combo"):
            self._guided_format_combo.setCurrentText("auto")
        self._reach_guided_step("Select data")
        idx = self._guided_step_index("Select data")
        self._guided_workflow_stepper.setCurrentRow(idx)

    def _on_guided_start_open_results(self) -> None:
        loaded = self._prompt_open_completed_results()
        if loaded:
            self._set_guided_workflow_mode("open_results")
            self._reach_guided_step("Correction approach")
            self._refresh_guided_start_panel()
            self._refresh_guided_diagnostics_panel()
            idx = self._guided_step_index("Correction approach")
            self._guided_workflow_stepper.setCurrentRow(idx)

    def _on_guided_switch_to_new_analysis_setup(self) -> None:
        self._set_guided_workflow_mode("new_analysis")
        if hasattr(self, "_guided_format_combo"):
            self._guided_format_combo.setCurrentText("auto")
        self._reach_guided_step("Select data")
        idx = self._guided_step_index("Select data")
        self._guided_workflow_stepper.setCurrentRow(idx)

    def _on_guided_go_to_diagnostics(self) -> None:
        idx = self._guided_step_index("Correction approach")
        self._guided_workflow_stepper.setCurrentRow(idx)

    def _guided_step_index(self, step_name: str) -> int:
        """Return one semantic Guided step index."""
        return GUIDED_WORKFLOW_STEPS.index(step_name)

    def _guided_current_step_name(self) -> str | None:
        """Return the semantic name of the currently selected Guided step,
        independent of Qt widget visibility (works even before .show())."""
        stepper = getattr(self, "_guided_workflow_stepper", None)
        if stepper is None:
            return None
        row = stepper.currentRow()
        if 0 <= row < len(GUIDED_WORKFLOW_STEPS):
            return GUIDED_WORKFLOW_STEPS[row]
        return None

    def _sync_line_edit_value(self, target: QLineEdit, text: str) -> None:
        if getattr(self, "_guided_setup_syncing", False):
            return
        if target.text() == text:
            return
        target.setText(text)

    def _on_guided_format_changed(self, _idx: int) -> None:
        """Change format without hidden file inspection or ROI discovery."""
        if getattr(self, "_guided_setup_syncing", False):
            return
        self._discovery_cache = None
        self._rwd_contract_cache = None
        if hasattr(self, "_guided_format_help_label"):
            selected = self._guided_format_combo.currentText().strip().lower()
            self._guided_format_help_label.setText(
                "Auto will detect the data format when you select ROIs."
                if selected == "auto"
                else "This format was selected manually. Select ROIs to check "
                "the recording."
            )
        if hasattr(self, "_roi_list"):
            blocker = QSignalBlocker(self._roi_list)
            self._roi_list.clear()
            del blocker
        if hasattr(self, "_guided_roi_list"):
            blocker = QSignalBlocker(self._guided_roi_list)
            self._guided_roi_list.clear()
            del blocker
        if hasattr(self, "_sessions_list"):
            self._sessions_list.clear()
        if hasattr(self, "_rep_session_combo"):
            blocker = QSignalBlocker(self._rep_session_combo)
            self._rep_session_combo.clear()
            self._rep_session_combo.addItem("(auto)")
            del blocker
        if hasattr(self, "_roi_selection_container"):
            self._roi_selection_container.setVisible(False)
        if hasattr(self, "_discovery_summary"):
            self._discovery_summary.setText(
                "ROI discovery is required after changing format."
            )
        if hasattr(self, "_guided_discovery_summary_label"):
            self._guided_discovery_summary_label.setText(
                "Format changed. Select ROIs to run discovery for the "
                "selected input."
            )
        if hasattr(self, "_format_combo"):
            blocker = QSignalBlocker(self._format_combo)
            self._sync_combo_text_value(
                self._format_combo,
                self._guided_format_combo.currentText(),
            )
            del blocker
        self._validation_passed = False
        self._validated_run_signature = None
        if hasattr(self, "_guided_diagnostics_status"):
            self._guided_diagnostics_status = "not_generated"
        if hasattr(self, "_run_btn"):
            self._run_btn.setEnabled(False)
        self._sync_guided_recording_visibility()
        self._refresh_guided_setup_summary(lightweight=True)
        self._invalidate_guided_backend_validation("input format changed")

    def _sync_combo_text_value(self, target: QComboBox, text: str) -> None:
        if getattr(self, "_guided_setup_syncing", False):
            return
        idx = target.findText(text)
        if idx >= 0 and target.currentIndex() != idx:
            target.setCurrentIndex(idx)

    def _sync_combo_data_value(self, target: QComboBox, data: object) -> None:
        if getattr(self, "_guided_setup_syncing", False):
            return
        idx = target.findData(data)
        if idx >= 0 and target.currentIndex() != idx:
            target.setCurrentIndex(idx)

    def _sync_spin_value(self, target: QDoubleSpinBox, value: float) -> None:
        if getattr(self, "_guided_setup_syncing", False):
            return
        if abs(float(target.value()) - float(value)) <= 1e-9:
            return
        target.setValue(float(value))

    def _sync_checkbox_value(self, target: QCheckBox, checked: bool) -> None:
        if getattr(self, "_guided_setup_syncing", False):
            return
        if target.isChecked() == bool(checked):
            return
        target.setChecked(bool(checked))

    def _set_combo_data_without_signals(self, combo: QComboBox, data: object) -> None:
        idx = combo.findData(data)
        if idx >= 0:
            combo.setCurrentIndex(idx)

    def _sync_guided_setup_from_full(self) -> None:
        """Refresh Guided setup controls from the existing Full Control widgets."""
        if getattr(self, "_guided_setup_syncing", False):
            return
        required = (
            "_guided_input_dir_edit",
            "_guided_output_dir_edit",
            "_guided_format_combo",
            "_guided_acquisition_mode_combo",
            "_guided_sessions_per_hour_edit",
            "_guided_session_duration_edit",
            "_guided_continuous_window_sec_spin",
            "_guided_allow_partial_final_window_cb",
            "_guided_exclude_incomplete_final_rwd_chunk_cb",
        )
        if not all(hasattr(self, name) for name in required):
            return
        self._guided_setup_syncing = True
        try:
            blockers = [
                QSignalBlocker(self._guided_input_dir_edit),
                QSignalBlocker(self._guided_output_dir_edit),
                QSignalBlocker(self._guided_format_combo),
                QSignalBlocker(self._guided_acquisition_mode_combo),
                QSignalBlocker(self._guided_sessions_per_hour_edit),
                QSignalBlocker(self._guided_session_duration_edit),
                QSignalBlocker(self._guided_continuous_window_sec_spin),
                QSignalBlocker(self._guided_allow_partial_final_window_cb),
                QSignalBlocker(self._guided_exclude_incomplete_final_rwd_chunk_cb),
            ]
            self._guided_input_dir_edit.setText(self._input_dir.text())
            self._guided_output_dir_edit.setText(self._output_dir.text())
            fmt_idx = self._guided_format_combo.findText(self._format_combo.currentText())
            if fmt_idx >= 0:
                self._guided_format_combo.setCurrentIndex(fmt_idx)
            self._set_combo_data_without_signals(
                self._guided_acquisition_mode_combo,
                self._selected_acquisition_mode(),
            )
            self._guided_sessions_per_hour_edit.setText(self._sph_edit.text())
            self._guided_session_duration_edit.setText(self._duration_edit.text())
            self._guided_continuous_window_sec_spin.setValue(float(self._continuous_window_sec_spin.value()))
            self._guided_allow_partial_final_window_cb.setChecked(
                bool(self._allow_partial_final_window_cb.isChecked())
            )
            self._guided_exclude_incomplete_final_rwd_chunk_cb.setChecked(
                bool(self._exclude_incomplete_final_rwd_chunk_cb.isChecked())
            )
            del blockers
        finally:
            self._guided_setup_syncing = False
        self._sync_guided_recording_visibility()
        self._refresh_guided_setup_summary()
        self._refresh_guided_navigation_state()

    def _sync_guided_recording_visibility(self) -> None:
        if not hasattr(self, "_guided_recording_structure_help_label"):
            return
        continuous = self._selected_acquisition_mode() == "continuous"
        for widget in (
            getattr(self, "_guided_intermittent_explanation_label", None),
            getattr(
                self, "_guided_recording_timing_inference_label", None
            ),
            getattr(self, "_guided_sessions_per_hour_label", None),
            getattr(self, "_guided_sessions_per_hour_edit", None),
            getattr(self, "_guided_session_duration_label", None),
            getattr(self, "_guided_session_duration_edit", None),
        ):
            if widget is not None:
                widget.setVisible(not continuous)
        for widget in (
            getattr(self, "_guided_continuous_window_label", None),
            getattr(self, "_guided_continuous_window_sec_spin", None),
            getattr(
                self, "_guided_allow_partial_final_window_label", None
            ),
            getattr(self, "_guided_allow_partial_final_window_cb", None),
        ):
            if widget is not None:
                widget.setVisible(continuous)
        resolved_format = str(
            (getattr(self, "_discovery_cache", None) or {}).get(
                "resolved_format",
                self._guided_format_combo.currentText(),
            )
        ).strip().lower()
        if hasattr(self, "_guided_incomplete_final_rwd_group"):
            self._guided_incomplete_final_rwd_group.setVisible(
                not continuous and resolved_format == "rwd"
            )
        self._refresh_guided_use_detected_timing_action()
        if continuous:
            self._guided_session_duration_label.setText(
                "Session duration (s):"
            )
            self._guided_session_duration_edit.setPlaceholderText(
                "(not used in continuous mode)"
            )
            self._guided_session_duration_edit.setToolTip(
                self._duration_edit.toolTip()
            )
            self._guided_recording_structure_help_label.setText(
                "Continuous mode uses one uninterrupted recording split into "
                "non-overlapping analysis windows. Continuous acquisition is "
                "outside the current Guided Run scope."
            )
            self._refresh_guided_navigation_state()
            return

        input_format = (
            resolved_format
        )
        if input_format != "rwd":
            self._guided_session_duration_label.setText(
                "Session duration (s):"
            )
            self._guided_session_duration_edit.setPlaceholderText(
                "(required, seconds > 0)"
            )
            self._guided_session_duration_edit.setToolTip(
                self._duration_edit.toolTip()
            )
            self._guided_recording_structure_help_label.setText(
                "Intermittent NPM is supported. Confirm sessions per hour and "
                "session duration before continuing."
                if input_format == "npm"
                else "Confirm sessions per hour and session duration before "
                "continuing."
            )
            self._refresh_guided_navigation_state()
            return

        self._guided_session_duration_label.setText(
            "Session duration (s):"
        )
        self._guided_session_duration_edit.setPlaceholderText(
            "(required, seconds > 0)"
        )
        self._guided_session_duration_edit.setToolTip(
            "Required for RWD intermittent recordings. Enter the positive "
            "recording duration for each session, in seconds."
        )
        sessions_per_hour = None
        try:
            sessions_per_hour = int(
                self._guided_sessions_per_hour_edit.text().strip()
            )
        except (AttributeError, ValueError):
            pass
        session_duration = None
        try:
            session_duration = float(
                self._guided_session_duration_edit.text().strip()
            )
        except (AttributeError, ValueError):
            pass
        if (
            sessions_per_hour is not None
            and sessions_per_hour > 0
            and session_duration is not None
            and session_duration > 0
            and sessions_per_hour * session_duration <= 3600
        ):
            # Detected settings are already visible in the fields above and
            # "Recording structure is ready." is shown near Continue; avoid
            # a third redundant restatement here.
            self._guided_recording_structure_help_label.setText("")
        else:
            if (
                sessions_per_hour is not None
                and sessions_per_hour > 0
                and session_duration is not None
                and session_duration > 0
                and sessions_per_hour * session_duration > 3600
            ):
                self._guided_recording_structure_help_label.setText(
                    "Recording structure needs attention: session timing is "
                    "impossible because sessions per hour × session duration "
                    "cannot exceed 3600 seconds."
                )
            else:
                self._guided_recording_structure_help_label.setText(
                    "Recording structure needs attention: positive "
                    "sessions/hour and session duration are required for RWD "
                    "intermittent input."
                )
        self._refresh_guided_navigation_state()

    def _guided_roi_discovery_diag(self, label: str, **fields) -> None:
        if (
            not GUIDED_DISCOVERY_DIAGNOSTICS
            or self._guided_roi_discovery_diag_start is None
        ):
            return
        elapsed = time.monotonic() - self._guided_roi_discovery_diag_start
        thread_id = threading.get_ident()
        thread_name = (
            "GUI"
            if thread_id == self._guided_roi_discovery_gui_thread_id
            else threading.current_thread().name
        )
        details = " ".join(
            f"{key}={value!r}" for key, value in fields.items()
        )
        line = (
            f"GUIDED_DISCOVERY_DIAG +{elapsed:.3f}s "
            f"thread={thread_name} thread_id={thread_id} "
            f"label={label}"
        )
        if details:
            line += " " + details
        self._append_log(line)

    def _on_guided_discovery_diag_event(
        self, event: dict[str, object]
    ) -> None:
        if not GUIDED_DISCOVERY_DIAGNOSTICS:
            return
        fields = dict(event.get("fields") or {})
        fields["worker_elapsed_sec"] = round(
            float(event.get("elapsed_sec") or 0.0), 6
        )
        fields["worker_thread_id"] = event.get("thread_id")
        fields["worker_is_gui_thread"] = (
            event.get("thread_id") == event.get("gui_thread_id")
        )
        self._guided_roi_discovery_diag(
            str(event.get("label") or "worker_event"), **fields
        )

    def _set_guided_roi_discovery_running(
        self, running: bool, *, succeeded: bool | None = None
    ) -> None:
        self._guided_roi_discovery_running = bool(running)
        self._guided_discover_rois_btn.setEnabled(not running)
        self._guided_discover_rois_btn.setText(
            "Discovering..." if running else "Select ROIs..."
        )
        self._guided_roi_discovery_progress.setVisible(bool(running))
        for widget in (
            self._guided_input_dir_edit,
            self._guided_input_browse_btn,
            self._guided_output_dir_edit,
            self._guided_output_browse_btn,
            self._guided_format_combo,
        ):
            widget.setEnabled(not running)
        if running:
            self._guided_discovery_summary_label.setText(
                "Discovering ROIs..."
            )
        elif succeeded is False:
            self._guided_discovery_summary_label.setText(
                "ROI discovery failed. Check the selected input and try again."
            )

    def _on_guided_discover_rois(self) -> None:
        """Start shared discovery off the GUI thread."""
        self._guided_discovery_requested_format = (
            self._guided_format_combo.currentText().strip().lower()
        )
        if not self._guided_roi_discovery_running:
            self._guided_roi_discovery_diag_start = time.monotonic()
        self._guided_roi_discovery_diag("handler_entered")
        if self._guided_roi_discovery_running:
            self._guided_roi_discovery_diag("duplicate_guard_return")
            return
        self._guided_roi_discovery_diag("input_validation_start")
        input_dir = self._input_dir.text().strip()
        config_path = self._active_config_source_path()
        if not input_dir or not os.path.isdir(input_dir):
            self._guided_roi_discovery_diag(
                "input_validation_failed", reason="invalid_input_dir"
            )
            QMessageBox.warning(
                self,
                "ROI Selection Error",
                "Select a valid input directory first.",
            )
            self._guided_roi_discovery_diag_start = None
            return
        if not config_path or not os.path.isfile(config_path):
            self._guided_roi_discovery_diag(
                "input_validation_failed", reason="invalid_config_path"
            )
            message = (
                "Select a valid custom config YAML first."
                if self._is_custom_config_enabled()
                else f"Default lab baseline config is missing:\n{config_path}"
            )
            QMessageBox.warning(
                self, "ROI Selection Error", message
            )
            self._guided_roi_discovery_diag_start = None
            return

        self._set_guided_roi_discovery_running(True)
        self._guided_roi_discovery_diag(
            "busy_state_set", input=input_dir, config=config_path
        )
        QApplication.processEvents(QEventLoop.ExcludeUserInputEvents)
        try:
            snapshot_started = time.monotonic()
            self._guided_roi_discovery_diag("discovery_snapshot_start")
            snapshot = self._snapshot_guided_discovery_inputs()
            self._guided_roi_discovery_diag(
                "discovery_snapshot_end",
                duration_sec=time.monotonic() - snapshot_started,
            )
        except Exception as exc:
            self._guided_roi_discovery_diag(
                "discovery_snapshot_failure",
                exception_type=type(exc).__name__,
                message=str(exc),
            )
            self._on_guided_roi_discovery_failed(
                f"{type(exc).__name__}: {exc}"
            )
            return

        self._guided_roi_discovery_diag("thread_worker_create_start")
        thread = QThread(self)
        worker = _GuidedRoiDiscoveryWorker(
            snapshot,
            self._build_discovery_spec_from_snapshot,
            start_monotonic=self._guided_roi_discovery_diag_start,
            gui_thread_id=self._guided_roi_discovery_gui_thread_id,
        )
        worker.moveToThread(thread)
        self._guided_roi_discovery_thread = thread
        self._guided_roi_discovery_worker = worker
        thread.started.connect(worker.run)
        worker.diagnostic.connect(
            self._on_guided_discovery_diag_event
        )
        worker.succeeded.connect(
            self._on_guided_roi_discovery_succeeded
        )
        worker.failed.connect(self._on_guided_roi_discovery_failed)
        worker.succeeded.connect(thread.quit)
        worker.failed.connect(thread.quit)
        worker.succeeded.connect(worker.deleteLater)
        worker.failed.connect(worker.deleteLater)
        thread.finished.connect(thread.deleteLater)
        thread.finished.connect(
            self._cleanup_guided_roi_discovery_worker
        )
        self._guided_roi_discovery_diag("thread_start_before")
        thread.start()
        self._guided_roi_discovery_diag("thread_start_after")

    def _on_guided_roi_discovery_succeeded(
        self, discovery: dict[str, object]
    ) -> None:
        self._guided_roi_discovery_diag(
            "success_slot_entered",
            sessions=len(discovery.get("sessions", [])),
            rois=len(discovery.get("rois", [])),
        )
        self._discovery_cache = discovery
        resolved_format = str(
            discovery.get("resolved_format") or ""
        ).strip().lower()
        if resolved_format in FORMAT_CHOICES:
            with QSignalBlocker(self._guided_format_combo):
                self._guided_format_combo.setCurrentText(resolved_format)
            with QSignalBlocker(self._format_combo):
                self._format_combo.setCurrentText(resolved_format)
        if hasattr(self, "_guided_format_help_label"):
            requested_format = str(
                getattr(self, "_guided_discovery_requested_format", "auto")
            ).strip().lower()
            self._guided_format_help_label.setText(
                f"Detected format: {resolved_format.upper()}. The app detected "
                "this format automatically."
                if requested_format == "auto"
                else f"Confirmed format: {resolved_format.upper()}."
            )
        populate_started = time.monotonic()
        self._guided_roi_discovery_diag("populate_discovery_ui_before")
        self._populate_discovery_ui(discovery)
        self._guided_roi_discovery_diag(
            "populate_discovery_ui_after",
            duration_sec=time.monotonic() - populate_started,
        )
        self._append_log(
            "ROI selection ready: "
            f"{len(discovery.get('rois', []))} ROIs found "
            f"(format={discovery.get('resolved_format', '?')})."
        )
        self._guided_roi_discovery_diag("busy_state_clear_before")
        self._set_guided_roi_discovery_running(
            False, succeeded=True
        )
        self._guided_roi_discovery_diag("busy_state_clear_after")
        self._guided_roi_discovery_diag(
            "navigation_refresh_before"
        )
        self._refresh_guided_navigation_state()
        self._guided_roi_discovery_diag(
            "navigation_refresh_after"
        )
        self._guided_roi_discovery_diag(
            "complete",
            total_sec=(
                time.monotonic()
                - self._guided_roi_discovery_diag_start
            ),
        )
        self._guided_roi_discovery_diag("success_slot_exiting")

    def _on_guided_roi_discovery_failed(self, message: str) -> None:
        self._guided_roi_discovery_diag(
            "failure_slot_entered", message=message
        )
        self._discovery_cache = None
        self._discovery_summary.setText("Discovery failed.")
        self._sessions_list.clear()
        self._roi_list.clear()
        self._guided_roi_list.clear()
        if hasattr(self, "_roi_selection_container"):
            self._roi_selection_container.setVisible(False)
        self._rep_session_combo.clear()
        self._rep_session_combo.addItem("(auto)")
        self._append_log(f"Discovery error: {message}")
        self._set_guided_roi_discovery_running(
            False, succeeded=False
        )
        self._refresh_guided_navigation_state()
        self._guided_roi_discovery_diag(
            "complete",
            total_sec=(
                time.monotonic()
                - self._guided_roi_discovery_diag_start
            ),
            status="failed",
        )
        QMessageBox.critical(
            self,
            "ROI Selection Failed",
            self._guided_roi_discovery_failure_message(message),
        )
        if self._guided_roi_discovery_thread is None:
            self._guided_roi_discovery_diag_start = None

    @staticmethod
    def _guided_roi_discovery_failure_message(message: str) -> str:
        """Return an actionable scientist-facing discovery failure.

        The full parser error remains in the application log for support,
        but it is not useful as the primary instruction in a blocking dialog.
        """
        lowered = str(message or "").lower()
        if "no recognizable rwd header" in lowered or "header row" in lowered:
            return (
                "The selected recording does not contain a recognizable "
                "fluorescence header. Check that you selected the folder "
                "containing the recording-session folders and their "
                "Fluorescence.csv files."
            )
        if "fs mismatch" in lowered or "sampling" in lowered:
            return (
                "The recording files do not agree on their sampling rate. "
                "Check that all selected session folders belong to the same "
                "recording, then try Select ROIs again."
            )
        if "suffix mismatch" in lowered or "time column mismatch" in lowered:
            return (
                "The recording files do not use the same channel layout. "
                "Check that all selected session folders belong to the same "
                "recording, then try Select ROIs again."
            )
        if "no usable roi" in lowered or "no roi" in lowered:
            return (
                "No usable signal/reference channel pairs were found. Check "
                "that the selected folder contains Fluorescence.csv files "
                "with matching 410 and 470 channels."
            )
        return (
            "The selected input could not be read as one consistent "
            "recording. Check the selected folder and its Fluorescence.csv "
            "files, then try Select ROIs again."
        )

    def _cleanup_guided_roi_discovery_worker(self) -> None:
        self._guided_roi_discovery_diag("worker_thread_cleanup")
        self._guided_roi_discovery_worker = None
        self._guided_roi_discovery_thread = None
        self._guided_roi_discovery_diag_start = None

    def closeEvent(self, event) -> None:
        if getattr(self, "_guided_backend_execution_active", False):
            QMessageBox.information(
                self,
                "Guided Run In Progress",
                "Guided Run is still running. Wait for it to finish before "
                "closing.",
            )
            event.ignore()
            return
        thread = getattr(self, "_guided_roi_discovery_thread", None)
        if thread is not None and thread.isRunning():
            thread.quit()
            thread.wait()
        review_thread = getattr(
            self, "_guided_completed_review_load_thread", None
        )
        if review_thread is not None and review_thread.isRunning():
            review_thread.quit()
            review_thread.wait()
        super().closeEvent(event)

    def _on_guided_recording_timing_user_edit(self, _text: str) -> None:
        if self._guided_recording_timing_applying:
            return
        self._guided_recording_timing_user_edited = True
        self._guided_recording_timing_inference_label.setText(
            "Using manually entered session timing."
        )
        self._refresh_guided_use_detected_timing_action()

    def _guided_detected_timing_available(self) -> bool:
        inference = self._guided_recording_timing_inference
        return bool(
            isinstance(inference, GuidedRecordingStructureInference)
            and inference.status == "inferred"
            and inference.sessions_per_hour is not None
            and inference.session_duration_sec is not None
        )

    def _refresh_guided_use_detected_timing_action(self) -> None:
        if not hasattr(self, "_guided_use_detected_timing_btn"):
            return
        intermittent = (
            self._selected_acquisition_mode() == "intermittent"
        )
        available = self._guided_detected_timing_available()
        differs = False
        if available:
            inference = self._guided_recording_timing_inference
            differs = (
                self._guided_sessions_per_hour_edit.text().strip()
                != str(inference.sessions_per_hour)
                or self._guided_session_duration_edit.text().strip()
                != f"{inference.session_duration_sec:g}"
            )
        show = bool(
            intermittent
            and available
            and (self._guided_recording_timing_user_edited or differs)
        )
        self._guided_use_detected_timing_btn.setVisible(show)
        self._guided_use_detected_timing_btn.setEnabled(show)

    def _apply_guided_detected_timing(self) -> None:
        if not self._guided_detected_timing_available():
            return
        inference = self._guided_recording_timing_inference
        self._guided_recording_timing_applying = True
        try:
            self._guided_sessions_per_hour_edit.setText(
                str(inference.sessions_per_hour)
            )
            self._guided_session_duration_edit.setText(
                f"{inference.session_duration_sec:g}"
            )
        finally:
            self._guided_recording_timing_applying = False
        self._guided_recording_timing_user_edited = False
        self._guided_recording_timing_inference_label.setText(
            inference.message
        )
        self._refresh_guided_navigation_state()
        self._refresh_guided_use_detected_timing_action()

    def _on_guided_use_detected_timing(self) -> None:
        self._apply_guided_detected_timing()

    @staticmethod
    def _guided_recording_timing_discovery_key(
        discovery: dict[str, object],
    ) -> tuple[str, tuple[str, ...]]:
        return (
            os.path.realpath(str(discovery.get("input_dir") or "")),
            tuple(
                os.path.realpath(str(session.get("path") or ""))
                for session in discovery.get("sessions", [])
                if isinstance(session, dict)
            ),
        )

    def _infer_guided_recording_timing_from_discovery(
        self,
    ) -> GuidedRecordingStructureInference:
        infer_started = time.monotonic()
        discovery = getattr(self, "_discovery_cache", None) or {}
        resolved_format = str(
            discovery.get("resolved_format")
            or self._guided_format_combo.currentText()
        ).strip().lower()
        source_path = str(
            discovery.get("input_dir")
            or self._guided_input_dir_edit.text()
        )
        contracts: list[dict[str, object]] = []
        sessions = [
            session
            for session in discovery.get("sessions", [])
            if isinstance(session, dict) and session.get("path")
        ]
        self._guided_roi_discovery_diag(
            "recording_timing_infer_start",
            resolved_format=resolved_format,
            sessions=len(sessions),
        )
        if resolved_format == "rwd":
            try:
                sample_indices = sorted(
                    {
                        0,
                        len(sessions) // 2,
                        len(sessions) - 1,
                    }
                ) if sessions else []
                for index in sample_indices:
                    session = sessions[index]
                    path = str(session["path"])
                    session_id = str(session.get("session_id") or "")
                    sample_started = time.monotonic()
                    self._guided_roi_discovery_diag(
                        "rwd_contract_sample_before",
                        sample_index=index,
                        session_id=session_id,
                        path=path,
                    )
                    contract = self._infer_rwd_chunk_contract(path)
                    contracts.append(
                        {
                            **contract,
                            "sample_session_id": session_id,
                        }
                    )
                    self._guided_roi_discovery_diag(
                        "rwd_contract_sample_after",
                        sample_index=index,
                        session_id=session_id,
                        duration_sec=(
                            time.monotonic() - sample_started
                        ),
                        inferred_duration_sec=contract.get(
                            "chunk_duration_sec"
                        ),
                    )
            except Exception as exc:
                self._guided_roi_discovery_diag(
                    "recording_timing_infer_end",
                    duration_sec=time.monotonic() - infer_started,
                    sampled_contracts=len(contracts),
                    status="failed",
                    exception_type=type(exc).__name__,
                )
                return GuidedRecordingStructureInference(
                    supported=True,
                    status="failed",
                    evidence={
                        "resolved_format": resolved_format,
                        "source_path": source_path,
                        "error": f"{type(exc).__name__}: {exc}",
                    },
                    message=(
                        "Could not confidently detect session timing. Enter "
                        "sessions per hour and session duration manually."
                    ),
                )
        result = infer_guided_recording_structure(
            discovery,
            source_path,
            resolved_format,
            rwd_chunk_contracts=contracts,
        )
        self._guided_roi_discovery_diag(
            "recording_timing_infer_end",
            duration_sec=time.monotonic() - infer_started,
            sampled_contracts=len(contracts),
            status=result.status,
        )
        return result

    def _refresh_guided_recording_timing_inference(self) -> None:
        refresh_started = time.monotonic()
        self._guided_roi_discovery_diag(
            "recording_timing_refresh_start"
        )
        if (
            not hasattr(self, "_guided_recording_timing_inference_label")
            or getattr(self, "_discovery_cache", None) is None
        ):
            self._guided_roi_discovery_diag(
                "recording_timing_refresh_end",
                duration_sec=time.monotonic() - refresh_started,
                outcome="unavailable",
            )
            return
        discovery = self._discovery_cache
        source_key = self._guided_recording_timing_discovery_key(discovery)
        new_source = source_key != self._guided_recording_timing_source_key
        if new_source:
            self._guided_recording_timing_source_key = source_key
            self._guided_recording_timing_user_edited = False
        if self._guided_recording_timing_user_edited and not new_source:
            self._guided_recording_timing_inference_label.setText(
                "Using manually entered session timing."
            )
            self._refresh_guided_use_detected_timing_action()
            self._guided_roi_discovery_diag(
                "recording_timing_refresh_end",
                duration_sec=time.monotonic() - refresh_started,
                outcome="manual_preserved",
            )
            return

        self._guided_roi_discovery_diag(
            "recording_timing_infer_before"
        )
        inference = self._infer_guided_recording_timing_from_discovery()
        self._guided_roi_discovery_diag(
            "recording_timing_infer_after",
            status=inference.status,
        )
        self._guided_recording_timing_inference = inference
        self._guided_recording_timing_inference_label.setText(
            inference.message
        )
        if (
            inference.status != "inferred"
            or inference.sessions_per_hour is None
            or inference.session_duration_sec is None
        ):
            self._refresh_guided_use_detected_timing_action()
            self._guided_roi_discovery_diag(
                "recording_timing_refresh_end",
                duration_sec=time.monotonic() - refresh_started,
                outcome=inference.status,
            )
            return
        self._apply_guided_detected_timing()
        self._guided_roi_discovery_diag(
            "recording_timing_refresh_end",
            duration_sec=time.monotonic() - refresh_started,
            outcome="inferred_applied",
        )

    @staticmethod
    def _guided_discovery_status_text(disco: dict) -> str:
        """Plain-language ROI discovery status; independent of Full Control's label."""
        fmt = str(disco.get("resolved_format", "") or "").strip().upper() or "the detected"
        n_total = int(disco.get("n_total_discovered", 0) or 0)
        session_word = "session" if n_total == 1 else "sessions"
        return (
            f"Detected {fmt} data with {n_total} recording {session_word}. "
            "Channels detected below."
        )

    def _guided_roi_list_state(self) -> dict[str, bool]:
        """{roi_id: checked} snapshot of the current Guided ROI checklist."""
        if not hasattr(self, "_guided_roi_list"):
            return {}
        return {
            self._guided_roi_list.item(idx).text(): (
                self._guided_roi_list.item(idx).checkState() == Qt.Checked
            )
            for idx in range(self._guided_roi_list.count())
        }

    def _sync_guided_discovery_from_full(self) -> None:
        sync_started = time.monotonic()
        self._guided_roi_discovery_diag("guided_sync_start")
        if not hasattr(self, "_guided_roi_list"):
            self._guided_roi_discovery_diag(
                "guided_sync_skipped", reason="guided_roi_list_missing"
            )
            return
        previous_state = self._guided_roi_list_state()
        blockers = [QSignalBlocker(self._guided_roi_list)]
        self._guided_roi_list.clear()
        for idx in range(self._roi_list.count()):
            src = self._roi_list.item(idx)
            item = QListWidgetItem(src.text())
            item.setFlags(item.flags() | Qt.ItemIsUserCheckable)
            item.setCheckState(src.checkState())
            self._guided_roi_list.addItem(item)
        del blockers
        if previous_state and self._guided_roi_list_state() != previous_state:
            # The discovered ROI set or its included/excluded state
            # genuinely changed (new discovery results, or a bulk
            # Select All/Select None on the Full Control side) -- this
            # is analysis-defining and must invalidate immediately, not
            # only be caught later by the identity backstop.
            self._invalidate_guided_backend_validation(
                "ROI selection changed"
            )
        if hasattr(self, "_guided_discovery_summary_label"):
            if self._discovery_cache is None:
                self._guided_discovery_summary_label.setText(
                    "Select ROIs scans the input folder and lists the "
                    "channels found in the data."
                )
            else:
                self._guided_discovery_summary_label.setText(
                    self._guided_discovery_status_text(self._discovery_cache)
                )
        self._refresh_guided_setup_summary()
        self._sync_guided_recording_visibility()
        self._guided_roi_discovery_diag(
            "timing_inference_refresh_before"
        )
        self._refresh_guided_recording_timing_inference()
        self._guided_roi_discovery_diag(
            "timing_inference_refresh_after"
        )
        self._refresh_guided_navigation_state()
        self._guided_roi_discovery_diag(
            "guided_sync_end",
            duration_sec=time.monotonic() - sync_started,
        )

    def _on_guided_roi_item_changed(self, item: QListWidgetItem) -> None:
        if getattr(self, "_guided_setup_syncing", False):
            return
        row = self._guided_roi_list.row(item)
        if row < 0 or row >= self._roi_list.count():
            return
        full_item = self._roi_list.item(row)
        if full_item.checkState() != item.checkState():
            full_item.setCheckState(item.checkState())
        self._invalidate_guided_backend_validation("ROI selection changed")
        self._refresh_guided_navigation_state()

    def _on_full_control_roi_item_changed(self, _item: QListWidgetItem) -> None:
        self._on_config_changed()
        self._sync_guided_discovery_from_full()

    def _build_guided_correction_approach_step(self) -> QWidget:
        wrapper = QWidget()
        wrapper.setObjectName("guidedCorrectionApproachControls")
        wrapper_layout = QVBoxLayout(wrapper)
        wrapper_layout.setContentsMargins(0, 0, 0, 0)
        wrapper_layout.setSpacing(10)
        wrapper_layout.addWidget(self._build_guided_skipped_setup_banner("Correction approach"))
        guidance = QLabel(
            "Compare correction methods and choose one strategy for each "
            "included ROI. Nothing here starts the final analysis."
        )
        guidance.setObjectName("guidedCorrectionWorkflowGuidance")
        guidance.setWordWrap(True)
        wrapper_layout.addWidget(guidance)
        self._guided_correction_next_action_label = QLabel(
            "Next step: build correction evidence."
        )
        self._guided_correction_next_action_label.setObjectName(
            "guidedCorrectionNextAction"
        )
        self._guided_correction_next_action_label.setProperty(
            "guidedStatusPill", True
        )
        self._guided_correction_next_action_label.setWordWrap(True)
        wrapper_layout.addWidget(self._guided_correction_next_action_label)

        candidate_group = QGroupBox(
            "Correction method reference (preview only)",
            wrapper,
        )
        candidate_group.setObjectName("guidedHiddenMethodConfiguration")
        candidate_layout = QVBoxLayout(candidate_group)
        candidate_layout.setContentsMargins(10, 8, 10, 8)
        cards = QWidget()
        cards.setObjectName("guidedCorrectionCards")
        grid = QGridLayout(cards)
        grid.setContentsMargins(0, 0, 0, 0)
        grid.setSpacing(10)
        card_defs = [
            (
                "Robust Global Event-Reject Fit",
                "Default / recommended starting point",
                "Default guided correction candidate. Fits the reference relationship while excluding event-like periods that can contaminate the fit.",
                "recommended",
            ),
            (
                "Adaptive Event-Gated Fit",
                "Candidate",
                "Candidate for recordings where the signal-reference relationship may change over time. Preview diagnostics should be inspected before use.",
                "standard",
            ),
            (
                "Global Linear Regression",
                "Baseline comparison, not recommended for most long-duration recordings.",
                "Included because many users expect this field-standard baseline. It can fail when reference coupling changes or event-rich periods contaminate the fit.",
                "caution",
            ),
            (
                "Signal-Only F0",
                "Diagnostic only",
                "Additional evidence for cases where reference-based correction "
                "may be inappropriate. It is not a current Guided Run "
                "production route.",
                "standard",
            ),
            (
                "Decision-Support Audit",
                "Coming later / read-only evidence.",
                "Future advisory report that may summarize evidence for "
                "candidate strategies. It will not run analysis or silently "
                "choose a strategy.",
                "future",
            ),
        ]
        self._guided_correction_intent = ""
        self._guided_correction_select_buttons = {}
        self._guided_correction_cards = {}
        for idx, (title, badge, helper, badge_level) in enumerate(card_defs):
            card = self._build_guided_correction_card(title, badge, helper, badge_level=badge_level)
            self._guided_correction_cards[title] = card
            grid.addWidget(card, idx // 2, idx % 2)
        grid.setColumnStretch(0, 1)
        grid.setColumnStretch(1, 1)
        if not getattr(self, "_guided_correction_sync_connected", False):
            self._dynamic_fit_mode_combo.currentIndexChanged.connect(
                lambda _idx: self._sync_guided_correction_from_full()
            )
            self._guided_correction_sync_connected = True
        self._sync_guided_correction_from_full()
        candidate_layout.addWidget(cards)
        self._guided_method_configuration_group = candidate_group
        candidate_group.setVisible(False)

        wrapper_layout.addWidget(self._build_guided_diagnostics_step())
        wrapper_layout.addWidget(self._build_guided_confirm_strategy_step())
        self._guided_correction_continue_status = QLabel(
            "Confirm correction strategies for all included ROIs to continue."
        )
        self._guided_correction_continue_status.setObjectName(
            "guidedCorrectionContinueStatus"
        )
        self._guided_correction_continue_status.setProperty(
            "guidedSecondaryText", True
        )
        self._guided_correction_continue_status.setWordWrap(True)
        wrapper_layout.addWidget(self._guided_correction_continue_status)
        self._guided_correction_continue_btn = QPushButton(
            "Continue to Feature Detection"
        )
        self._guided_correction_continue_btn.setObjectName(
            "guidedCorrectionContinueButton"
        )
        self._guided_correction_continue_btn.clicked.connect(
            self._on_guided_continue_to_feature_detection
        )
        self._guided_correction_continue_btn.setEnabled(False)
        wrapper_layout.addWidget(self._guided_correction_continue_btn)
        return self._build_guided_step_scroll(
            "guidedStepCorrectionApproach",
            "Correction approach",
            [],
            wrapper,
        )

    def _build_guided_correction_card(self, title: str, badge: str, helper: str, *, badge_level: str) -> QGroupBox:
        safe_name = re.sub(r"[^A-Za-z0-9]+", "", title)
        card = QGroupBox(title)
        card.setObjectName(f"guidedCorrectionCard{safe_name}")
        card.setProperty("guidedCorrectionCardTitle", title)
        card.setProperty("guidedCorrectionCard", True)
        card.setProperty("guidedCorrectionCardNonExecuting", True)
        # Guided correction cards are deliberately non-executing; no clicked/changed signals are connected here.
        layout = QVBoxLayout(card)
        layout.setContentsMargins(12, 12, 12, 12)
        layout.setSpacing(8)
        badge_label = QLabel(badge)
        badge_label.setObjectName(f"guidedCorrectionCard{safe_name}Badge")
        badge_label.setProperty("guidedCardBadge", True)
        badge_label.setProperty("guidedCardBadgeLevel", badge_level)
        badge_label.setWordWrap(True)
        layout.addWidget(badge_label)
        helper_label = QLabel(helper)
        helper_label.setObjectName(f"guidedCorrectionCard{safe_name}Helper")
        helper_label.setProperty("guidedSecondaryText", True)
        helper_label.setWordWrap(True)
        layout.addWidget(helper_label)
        if title == GUIDED_SIGNAL_ONLY_F0_CARD:
            stage_text = (
                "Diagnostic only. Not used to produce the final analysis "
                "output."
            )
        elif title in GUIDED_REFERENCE_CORRECTION_CARD_TO_MODE:
            stage_text = (
                "Selects this method for the local preview below. Choosing "
                "the correction method for each ROI happens after you "
                "compare the preview evidence."
            )
        else:
            stage_text = (
                "Read-only method information. Final strategy confirmation "
                "happens after preview evidence is reviewed."
            )
        stage_label = QLabel(stage_text)
        stage_label.setObjectName(f"guidedCorrectionCard{safe_name}Stage")
        stage_label.setProperty("guidedMutedText", True)
        stage_label.setWordWrap(True)
        layout.addWidget(stage_label)
        if title in GUIDED_REFERENCE_CORRECTION_CARD_TO_MODE:
            select_btn = QPushButton("Preview this correction method")
            select_btn.setObjectName(f"guidedCorrectionSelect{safe_name}")
            select_btn.setToolTip(
                "Includes this method in the local correction preview "
                "below. It does not choose the final correction method for "
                "the ROI."
            )
            select_btn.clicked.connect(
                lambda _checked=False, card_title=title: self._select_guided_reference_correction_card(card_title)
            )
            self._guided_correction_select_buttons[title] = select_btn
            layout.addWidget(select_btn)
        elif title == GUIDED_SIGNAL_ONLY_F0_CARD:
            select_btn = QPushButton("Preview this correction method")
            select_btn.setObjectName(f"guidedCorrectionSelect{safe_name}")
            select_btn.setToolTip(
                "Includes Signal-Only F0 in the local correction preview "
                "below. It is diagnostic-only and is not used to produce "
                "the final analysis output."
            )
            select_btn.clicked.connect(self._select_guided_signal_only_f0_intent)
            self._guided_correction_select_buttons[title] = select_btn
            layout.addWidget(select_btn)
        return card

