    def _on_guided_feature_preview_roi_changed(self) -> None:
        self._refresh_guided_feature_preview_segment_choices()
        self._clear_guided_feature_detection_preview_result(
            "ROI changed. Generate preview to update."
        )

    def _guided_feature_preview_segments_for_roi(
        self, roi_id: str
    ) -> list[dict[str, object]]:
        """Return discovered previewable segments and retained-evidence identity."""
        evidence = self._guided_local_preview_evidence_for_roi(
            roi_id, require_current=True
        )
        result = (
            evidence.get("result")
            if isinstance(evidence, dict)
            and isinstance(evidence.get("result"), dict)
            else {}
        )
        provenance = (
            evidence.get("provenance")
            if isinstance(evidence, dict)
            and isinstance(evidence.get("provenance"), dict)
            else {}
        )
        retained_index = provenance.get(
            "selected_segment_index", result.get("chunk_index")
        )
        retained_source = os.path.realpath(
            str(
                provenance.get("source_file")
                or result.get("source_file")
                or ""
            )
        )
        retained_preview_id = str(
            result.get("preview_id")
            or provenance.get("preview_id")
            or ""
        )
        segments: list[dict[str, object]] = []
        discovery = getattr(self, "_discovery_cache", None) or {}
        for fallback_index, session in enumerate(
            discovery.get("sessions", ())
        ):
            if (
                not isinstance(session, dict)
                or not session.get("included_in_preview", True)
                or not session.get("path")
            ):
                continue
            index = int(session.get("index", fallback_index))
            source_path = os.path.realpath(str(session["path"]))
            label = str(session.get("session_id") or index)
            retained = bool(
                retained_preview_id
                and (
                    (
                        retained_index is not None
                        and int(retained_index) == index
                    )
                    or (
                        retained_source
                        and retained_source == source_path
                    )
                )
            )
            segments.append(
                {
                    "segment_label": label,
                    "discovered_session_index": index,
                    "source_path": source_path,
                    "adapter_chunk_index": 0,
                    "retained_preview_id": (
                        retained_preview_id if retained else ""
                    ),
                }
            )
        if not segments and retained_preview_id:
            segments.append(
                {
                    "segment_label": str(
                        provenance.get("selected_segment_label")
                        or result.get("preview_segment_label")
                        or "retained preview segment"
                    ),
                    "discovered_session_index": retained_index,
                    "source_path": retained_source,
                    "adapter_chunk_index": int(
                        result.get("adapter_local_chunk_id", 0)
                    ),
                    "retained_preview_id": retained_preview_id,
                }
            )
        return segments

    def _refresh_guided_feature_preview_segment_choices(self) -> None:
        if not hasattr(self, "_guided_feature_preview_segment_combo"):
            return
        roi_id = self._guided_feature_preview_roi_combo.currentText()
        segments = self._guided_feature_preview_segments_for_roi(roi_id)
        current_segment_index = None
        current_data = self._guided_feature_preview_segment_combo.currentData()
        if isinstance(current_data, dict):
            current_segment_index = current_data.get(
                "discovered_session_index"
            )
        with QSignalBlocker(self._guided_feature_preview_segment_combo):
            self._guided_feature_preview_segment_combo.clear()
            for segment in segments:
                self._guided_feature_preview_segment_combo.addItem(
                    str(segment["segment_label"]), dict(segment)
                )
            if current_segment_index is not None:
                for index in range(
                    self._guided_feature_preview_segment_combo.count()
                ):
                    data = self._guided_feature_preview_segment_combo.itemData(
                        index
                    )
                    if (
                        isinstance(data, dict)
                        and data.get("discovered_session_index")
                        == current_segment_index
                    ):
                        self._guided_feature_preview_segment_combo.setCurrentIndex(
                            index
                        )
                        break

    def _set_preview_table_row(self, row: int, parameter: str, value: str) -> None:
        self._guided_feature_preview_result_table.setItem(row, 0, QTableWidgetItem(parameter))
        self._guided_feature_preview_result_table.setItem(row, 1, QTableWidgetItem(value))

    def _refresh_guided_feature_detection_preview_panel(self) -> None:
        if not hasattr(self, "_guided_feature_preview_roi_combo"):
            return

        # Populate ROI selector with included ROIs
        included_rois = list(self._guided_selected_roi_ids()[1])
        current_roi = self._guided_feature_preview_roi_combo.currentText()

        with QSignalBlocker(self._guided_feature_preview_roi_combo):
            self._guided_feature_preview_roi_combo.clear()
            for roi in included_rois:
                self._guided_feature_preview_roi_combo.addItem(str(roi), str(roi))
            if current_roi in included_rois:
                self._guided_feature_preview_roi_combo.setCurrentText(current_roi)
            elif included_rois:
                self._guided_feature_preview_roi_combo.setCurrentIndex(0)

        self._refresh_guided_feature_preview_segment_choices()
        segment_available = (
            self._guided_feature_preview_segment_combo.count() > 0
        )
        if not included_rois:
            self._guided_feature_preview_generate_btn.setEnabled(False)
            self._guided_feature_preview_status_label.setText("No included ROIs available.")
        elif segment_available:
            self._guided_feature_preview_generate_btn.setEnabled(True)
            if self._guided_feature_preview_status_label.text() in ("No included ROIs available.", "Please generate a correction preview in Step 4 first."):
                self._guided_feature_preview_status_label.setText("Select an ROI and generate preview.")
        else:
            self._guided_feature_preview_generate_btn.setEnabled(False)
            self._guided_feature_preview_status_label.setText("Please generate a correction preview in Step 4 first.")

    def _build_guided_feature_detection_preview_context(self, roi_id: str) -> dict:
        context = {
            "dynamic_delta_f": {},
            "dynamic_dff": {},
            "signal_only_dff": {}
        }

        # Load local preview evidence for this ROI
        evidence = self._guided_local_preview_evidence_for_roi(roi_id, require_current=True)

        if not evidence or not isinstance(evidence, dict):
            return context

        result = evidence.get("result", {})
        if not result or not isinstance(result, dict):
            return context
        provenance = evidence.get("provenance", {})
        if not isinstance(provenance, dict):
            return context
        selected_segment = (
            self._guided_feature_preview_segment_combo.currentData()
            if hasattr(self, "_guided_feature_preview_segment_combo")
            else None
        )
        if isinstance(selected_segment, dict):
            selected_preview_id = str(
                selected_segment.get("retained_preview_id") or ""
            )
            evidence_preview_id = str(
                result.get("preview_id")
                or provenance.get("preview_id")
                or ""
            )
            if not selected_preview_id or (
                evidence_preview_id
                and selected_preview_id != evidence_preview_id
            ):
                return context

        # 3. Require evidence & result to be current and preview_only/production_analysis checks
        if result.get("preview_only") is not True or result.get("production_analysis") is not False:
            return context
        if provenance.get("preview_only") is not True or provenance.get("production_analysis") is not False:
            return context

        method_statuses = result.get("method_statuses", {})
        if isinstance(method_statuses, dict):
            for mode, raw_status in method_statuses.items():
                status = (
                    raw_status if isinstance(raw_status, dict) else {}
                )
                retained = status.get("local_preview_dff_evidence")
                if not (
                    status.get("status") == "success"
                    and isinstance(retained, dict)
                    and retained.get("valid") is True
                    and retained.get("current_or_stale") == "current"
                    and retained.get("preview_only") is True
                    and retained.get("production_analysis") is False
                    and retained.get("trace_source")
                    == "local_correction_preview_dff"
                    and retained.get("roi_id") == roi_id
                    and retained.get("dynamic_fit_mode") == mode
                ):
                    continue
                time_sec = retained.get("time_sec")
                preview_dff = retained.get("preview_dff")
                if time_sec is None or preview_dff is None:
                    continue
                time_array = np.asarray(time_sec, dtype=float).reshape(-1)
                trace_array = np.asarray(
                    preview_dff, dtype=float
                ).reshape(-1)
                if (
                    time_array.size < 2
                    or time_array.size != trace_array.size
                ):
                    continue
                median_dt = float(np.median(np.diff(time_array)))
                if not np.isfinite(median_dt) or median_dt <= 0:
                    continue
                context["dynamic_dff"][(roi_id, str(mode))] = {
                    "time_sec": time_array,
                    "trace": trace_array,
                    "fs_hz": 1.0 / median_dt,
                    "trace_identity": {
                        "roi_id": roi_id,
                        "trace_source": "local_correction_preview_dff",
                        "preview_id": str(result.get("preview_id") or ""),
                        "preview_only": True,
                        "production_analysis": False,
                        "dff_scale": retained.get("dff_scale"),
                        "baseline_scope": retained.get("baseline_scope"),
                    },
                    "correction_identity": {
                        "correction_strategy": "dynamic_fit",
                        "dynamic_fit_mode": str(mode),
                    },
                    "current": True,
                    "source_kind": "local_correction_preview",
                }

        sig_only_evidence = result.get("signal_only_f0_preview_evidence", {})
        if (
            sig_only_evidence
            and isinstance(sig_only_evidence, dict)
            and sig_only_evidence.get("valid") is True
            and sig_only_evidence.get("current_or_stale") == "current"
        ):
            time_sec = sig_only_evidence.get("time_sec")
            preview_dff = sig_only_evidence.get("preview_dff")

            if time_sec is not None and preview_dff is not None:
                # 2. Do not invent fs_hz for <=1 sample traces. dt must be finite and >0.
                if len(time_sec) < 2:
                    return context

                dt = np.diff(time_sec)
                median_dt = np.median(dt)
                if not np.isfinite(median_dt) or median_dt <= 0:
                    return context

                fs_hz = float(1.0 / median_dt)

                context["signal_only_dff"][roi_id] = {
                    "time_sec": time_sec,
                    "trace": preview_dff,
                    "fs_hz": fs_hz,
                    "trace_identity": {"roi_id": roi_id, "source": "in_memory_preview"},
                    "correction_identity": {"strategy": "signal_only_f0"},
                    "current": True,
                }
        return context

    def _guided_feature_preview_choice_is_current(
        self, choice: object
    ) -> bool:
        if not isinstance(choice, dict):
            return False
        return bool(
            choice.get("confirmed") is True
            and choice.get("current") is True
            and choice.get("stale") is not True
            and choice.get("preview_only") is True
            and choice.get("production_analysis") is False
            and choice.get("source_type")
            == LOCAL_CORRECTION_PREVIEW_SOURCE_TYPE
            and str(choice.get("setup_signature") or "")
            == self._guided_local_preview_setup_signature()
        )

    def _guided_feature_preview_config_overrides(
        self, segment: dict[str, object], input_format: str
    ) -> dict[str, object]:
        source_path = str(segment.get("source_path") or "")
        if input_format == "rwd":
            contract = self._infer_rwd_chunk_contract(source_path)
            return {
                "target_fs_hz": float(contract["fs_hz"]),
                "chunk_duration_sec": float(
                    contract["chunk_duration_sec"]
                ),
                "rwd_time_col": str(contract["time_col"]),
                "uv_suffix": str(contract["uv_suffix"]),
                "sig_suffix": str(contract["sig_suffix"]),
            }
        overrides = self._infer_dataset_contract_overrides(input_format)
        result = dict(overrides) if isinstance(overrides, dict) else {}
        duration_text = self._duration_edit.text().strip()
        if duration_text:
            result["chunk_duration_sec"] = float(duration_text)
        return result

    @staticmethod
    def _guided_feature_preview_context_from_trace(
        trace_result: dict[str, object],
        *,
        roi_id: str,
        correction_strategy: str,
        dynamic_fit_mode: str,
    ) -> dict[str, object]:
        context: dict[str, object] = {
            "dynamic_delta_f": {},
            "dynamic_dff": {},
            "signal_only_dff": {},
        }
        trace = {
            "time_sec": trace_result["time_sec"],
            "trace": trace_result["preview_dff"],
            "fs_hz": trace_result["fs_hz"],
            "current": True,
            "source_kind": "local_correction_preview",
        }
        if correction_strategy == "dynamic_fit":
            trace.update(
                trace_identity={
                    "roi_id": roi_id,
                    "trace_source": "local_correction_preview_dff",
                    "preview_only": True,
                    "production_analysis": False,
                    "dff_scale": "fractional_ratio",
                    "segment_label": trace_result.get("segment_label"),
                },
                correction_identity={
                    "correction_strategy": "dynamic_fit",
                    "dynamic_fit_mode": dynamic_fit_mode,
                },
            )
            context["dynamic_dff"] = {
                (roi_id, dynamic_fit_mode): trace
            }
        else:
            trace.update(
                trace_identity={
                    "roi_id": roi_id,
                    "source": "in_memory_preview",
                    "trace_source": "local_correction_preview_dff",
                    "preview_only": True,
                    "production_analysis": False,
                    "dff_scale": "fractional_ratio",
                    "segment_label": trace_result.get("segment_label"),
                },
                correction_identity={"strategy": "signal_only_f0"},
            )
            context["signal_only_dff"] = {roi_id: trace}
        return context

    def _on_guided_generate_feature_detection_preview(self) -> None:
        roi_id = self._guided_feature_preview_roi_combo.currentText()
        self._clear_guided_feature_detection_preview_result()

        if not roi_id:
            self._guided_feature_preview_status_label.setText("No ROI selected.")
            return

        # Get confirmed correction strategy for this ROI
        choice_key = self._guided_confirm_choice_key(
            LOCAL_CORRECTION_PREVIEW_SOURCE_TYPE, None, roi_id
        )
        choices = getattr(self, "_guided_strategy_choices", {})
        choice = choices.get(choice_key)
        if not self._guided_feature_preview_choice_is_current(choice):
            self._guided_feature_preview_status_label.setText(
                f"Correction strategy for {roi_id} is missing or stale. "
                "Return to Correction Approach and reconfirm it."
            )
            return

        strategy = choice.get("strategy", "")

        from photometry_pipeline.guided_new_analysis_plan import FIRST_SUBSET_DYNAMIC_FIT_STRATEGIES

        # Normalize dynamic-fit strategy; trace availability is checked below.
        is_dynamic_fit = (
            strategy in FIRST_SUBSET_DYNAMIC_FIT_STRATEGIES
            or choice.get("strategy_family") == "dynamic_fit"
        )

        segment = self._guided_feature_preview_segment_combo.currentData()
        if not isinstance(segment, dict):
            self._guided_feature_preview_status_label.setText(
                "No valid preview segment is selected."
            )
            return
        source_path = str(segment.get("source_path") or "")
        segment_index = segment.get("discovered_session_index")

        # Resolve this ROI's settings: its own effective (default-layered)
        # custom settings if it has been customized, otherwise the default
        # settings. Using the effective settings here -- not the possibly
        # sparse stored override -- keeps preview consistent with the
        # table/dialog and with what Run will actually use.
        roi_override = getattr(
            self, "_guided_per_roi_feature_event_overrides", {}
        ).get(roi_id)
        if roi_override:
            config_fields = self._guided_effective_feature_event_config_fields_for_roi(
                roi_id
            )
            err = None
            preview_settings_label = "Custom"
        else:
            config_fields, err = self._guided_feature_event_current_values()
            preview_settings_label = "Default"
        if err:
            self._guided_feature_preview_status_label.setText(f"Invalid feature settings: {err}")
            self._guided_feature_preview_result_table.setVisible(False)
            return
        # Drop threshold fields inactive for the selected method so a dormant
        # value (e.g. peak_threshold_abs=0.0 carried by a full effective
        # config while the method is mean_std) cannot block preview
        # validation. Applied to both the Default and Custom branches above so
        # both previews validate identically.
        config_fields = normalize_feature_settings_for_active_threshold_method(
            config_fields
        )

        from photometry_pipeline.guided_feature_detection_preview import (
            GuidedFeaturePreviewTraceRequest,
            build_guided_feature_detection_preview,
            GuidedFeaturePreviewUnsupportedError,
        )

        # Map dynamic mode normalization
        if is_dynamic_fit:
            correction_strategy = "dynamic_fit"
            dynamic_fit_mode = str(
                choice.get("dynamic_fit_mode")
                or (
                    strategy
                    if strategy in FIRST_SUBSET_DYNAMIC_FIT_STRATEGIES
                    else ""
                )
            )
        else:
            correction_strategy = strategy
            dynamic_fit_mode = ""

        request = GuidedFeaturePreviewTraceRequest(
            roi_id=roi_id,
            event_signal=config_fields.get("event_signal", "delta_f"),
            correction_strategy=correction_strategy,
            dynamic_fit_mode=dynamic_fit_mode,
            feature_settings=config_fields,
            feature_profile_id="preview-profile",
        )

        if correction_strategy == "dynamic_fit" and request.event_signal != "dff":
            self._guided_feature_preview_status_label.setText(
                "Feature preview is not available for dynamic-fit delta_f "
                "because this Step 5 path supports only local "
                "correction-preview dF/F."
            )
            return

        # Reuse retained evidence only when it belongs to the selected segment.
        context = self._build_guided_feature_detection_preview_context(roi_id)
        has_trace = (
            correction_strategy == "dynamic_fit"
            and (roi_id, dynamic_fit_mode)
            in context.get("dynamic_dff", {})
        ) or (
            correction_strategy == "signal_only_f0"
            and roi_id in context.get("signal_only_dff", {})
        )
        if not has_trace and request.event_signal == "dff":
            if not source_path or segment_index is None:
                self._guided_feature_preview_status_label.setText(
                    "The selected preview segment is unavailable."
                )
                return
            discovery = getattr(self, "_discovery_cache", None) or {}
            input_format = str(
                discovery.get("resolved_format")
                or self._guided_format_combo.currentText()
                or ""
            ).strip().lower()
            self._guided_feature_preview_status_label.setText(
                "Computing local preview for selected segment..."
            )
            self._guided_feature_preview_generate_btn.setEnabled(False)
            QApplication.processEvents()
            try:
                trace_result = (
                    compute_guided_local_preview_dff_trace_in_memory(
                        source_path,
                        roi=roi_id,
                        chunk_index=int(segment_index),
                        adapter_chunk_index=int(
                            segment.get("adapter_chunk_index", 0)
                        ),
                        segment_label=str(
                            segment.get("segment_label")
                            or segment_index
                        ),
                        input_format=input_format,
                        config_path=self._active_config_source_path(),
                        strategy_family=str(
                            choice.get("strategy_family")
                            or correction_strategy
                        ),
                        strategy=str(strategy),
                        dynamic_fit_mode=(
                            dynamic_fit_mode or None
                        ),
                        config_overrides=(
                            self._guided_feature_preview_config_overrides(
                                segment, input_format
                            )
                        ),
                    )
                )
            except Exception as exc:
                self._guided_feature_preview_status_label.setText(
                    f"Local preview computation failed: {exc}"
                )
                return
            finally:
                self._guided_feature_preview_generate_btn.setEnabled(
                    bool(
                        self._guided_feature_preview_roi_combo.currentText()
                        and self._guided_feature_preview_segment_combo.count()
                    )
                )
            if (
                not isinstance(trace_result, dict)
                or trace_result.get("valid") is not True
            ):
                issues = (
                    trace_result.get("issues", ())
                    if isinstance(trace_result, dict)
                    else ()
                )
                detail = str(next(iter(issues), "trace unavailable"))
                self._guided_feature_preview_status_label.setText(
                    f"Local preview computation failed: {detail}"
                )
                return
            self._guided_feature_preview_on_demand_trace = trace_result
            context = self._guided_feature_preview_context_from_trace(
                trace_result,
                roi_id=roi_id,
                correction_strategy=correction_strategy,
                dynamic_fit_mode=dynamic_fit_mode,
            )

        # Run preview
        try:
            result = build_guided_feature_detection_preview(
                trace_request=request,
                available_trace_context=context
            )
        except GuidedFeaturePreviewUnsupportedError as exc:
            # Map specific plain language messages
            exc_str = str(exc)
            if correction_strategy == "dynamic_fit" and request.event_signal == "dff":
                msg = (
                    "Preview is not available for dynamic-fit dF/F before Run because the current local "
                    "correction preview does not produce authoritative dF/F. Choose delta_f for preview, or proceed without preview."
                )
            elif correction_strategy == "signal_only_f0" and request.event_signal == "delta_f":
                msg = (
                    "Preview is not available for Signal-Only F0 with delta_f because no authoritative "
                    "Signal-Only delta-F preview is defined."
                )
            elif correction_strategy == "dynamic_fit":
                msg = (
                    f"Preview evidence for this ROI is not available in memory. Return to Correction "
                    "Approach and regenerate local preview, or proceed without preview."
                )
            elif "stale" in exc_str.lower() or choice.get("stale"):
                msg = "Correction preview evidence is stale. Return to Correction Approach and reconfirm the ROI."
            elif "not found" in exc_str or "No matching" in exc_str:
                msg = (
                    f"Preview evidence for {roi_id} is not available in memory. Return to Correction "
                    "Approach and regenerate local preview, or proceed without preview."
                )
            else:
                msg = exc_str
            self._guided_feature_preview_status_label.setText(msg)
            self._guided_feature_preview_result_table.setVisible(False)
            return
        except Exception as exc:
            self._guided_feature_preview_status_label.setText(f"Preview generation failed: {exc}")
            self._guided_feature_preview_result_table.setVisible(False)
            return

        # Success! Render results
        pos_peaks = len(result.positive_peak_indices) if result.positive_peak_indices is not None else 0
        neg_peaks = len(result.negative_peak_indices) if result.negative_peak_indices is not None else 0
        total_peaks = pos_peaks + neg_peaks
        thresh_up = f"{result.threshold_upper:.4f}" if result.threshold_upper is not None else "None"
        thresh_low = f"{result.threshold_lower:.4f}" if result.threshold_lower is not None else "None"

        self._set_preview_table_row(0, "ROI", result.roi_id)
        self._set_preview_table_row(1, "Event Signal", result.event_signal)
        self._set_preview_table_row(2, "Correction Strategy/Mode", f"{request.correction_strategy} / {request.dynamic_fit_mode or 'none'}")
        self._set_preview_table_row(3, "Positive Events", str(pos_peaks))
        self._set_preview_table_row(4, "Negative Events", str(neg_peaks))
        self._set_preview_table_row(5, "Total Events", str(total_peaks))
        self._set_preview_table_row(6, "Threshold Upper", thresh_up)
        self._set_preview_table_row(7, "Threshold Lower", thresh_low)
        self._set_preview_table_row(8, "Feature Settings Digest", result.feature_settings_digest)
        self._set_preview_table_row(9, "Safety Status", "Preview-only (no files written)")

        self._guided_feature_preview_last_result = result
        self._guided_feature_preview_plot.set_result(result)
        self._guided_feature_preview_source_note.setVisible(True)
        self._guided_feature_preview_details_toggle.setVisible(True)
        self._guided_feature_preview_result_table.setVisible(True)
        self._guided_feature_preview_status_label.setText(
            f"Previewing {roi_id} with {preview_settings_label} settings. "
            "Preview generated successfully."
        )

    def _on_guided_apply_feature_event_profile(self) -> None:
        if getattr(self, "_guided_workflow_mode", "start") == "new_analysis":
            self._on_guided_apply_feature_event_profile_new_analysis()
            return
        run_dir = self._current_guided_completed_run_dir()
        if not run_dir:
            self._guided_feature_event_status_label.setText(
                "Feature/event profile not applied: Open Results must be used first."
            )
            return
        config_fields, err = self._guided_feature_event_current_values()
        if err:
            self._guided_feature_event_status_label.setText(f"Feature/event profile not applied: {err}")
            return
        profile = FeatureEventProfile(
            profile_id="default-events",
            profile_label="Default feature/event profile",
            scope="run",
            status="complete",
            config_fields=dict(config_fields or {}),
            evidence_previews=[],
            choice_source="explicit_user_profile_edit",
            target_rois=[],
            resolved_rois=[],
            provenance_references=[],
        )
        profiles_by_run = getattr(self, "_guided_draft_feature_event_profiles_by_run", {})
        previous_profiles = list(profiles_by_run.get(run_dir, []))
        profiles_by_run[run_dir] = [profile]
        self._guided_draft_feature_event_profiles_by_run = profiles_by_run
        plan, preview_errors = self._build_guided_draft_run_plan()
        errors = list(preview_errors)
        if plan is not None:
            errors.extend(validate_plan_contract(plan))
        if errors:
            if previous_profiles:
                profiles_by_run[run_dir] = previous_profiles
            else:
                profiles_by_run.pop(run_dir, None)
            self._guided_draft_feature_event_profiles_by_run = profiles_by_run
            self._guided_feature_event_status_label.setText(
                "Feature/event profile not applied: " + "; ".join(errors)
            )
            self._refresh_guided_draft_run_plan_preview()
            return
        self._guided_feature_event_status_label.setText(
            "Feature/event profile applied to in-memory draft plan. No outputs were written."
        )
        self._guided_feature_event_editor_synced_run = run_dir
        self._refresh_guided_draft_run_plan_preview()

    def _on_guided_apply_feature_event_profile_new_analysis(self) -> None:
        config_fields, err = self._guided_feature_event_current_values()
        defaults_res = self._active_feature_event_defaults_result()
        baseline_path = defaults_res.baseline_source_path
        baseline_kind = defaults_res.baseline_source_kind
        
        current_format = self._guided_format_combo.currentText() if hasattr(self, "_guided_format_combo") else "auto"
        current_acq_mode = "continuous"
        if hasattr(self, "_guided_acquisition_mode_combo"):
            current_acq_mode = self._guided_acquisition_mode_combo.currentData() or self._guided_acquisition_mode_combo.currentText().lower()
            if not current_acq_mode:
                current_acq_mode = "continuous"

        if err:
            self._guided_new_analysis_feature_event_profile_status = "invalid"
            self._guided_new_analysis_feature_event_profile_errors = [err]
            self._guided_feature_event_status_label.setText(
                f"{GUIDED_DEFAULT_SETTINGS_NEED_ATTENTION} {err}"
            )
            self._refresh_guided_draft_run_plan_preview()
            return

        semantic_errors = validate_feature_event_config_fields(config_fields or {})
        if semantic_errors:
            self._guided_new_analysis_feature_event_profile_status = "invalid"
            self._guided_new_analysis_feature_event_profile_errors = semantic_errors
            self._guided_feature_event_status_label.setText(
                f"{GUIDED_DEFAULT_SETTINGS_NEED_ATTENTION} "
                + "; ".join(semantic_errors)
            )
            self._refresh_guided_draft_run_plan_preview()
            return
            
        import uuid
        profile_id = getattr(self, "_guided_new_analysis_feature_event_profile", {}).get("profile_id") if self._guided_new_analysis_feature_event_profile else None
        if not profile_id:
            profile_id = f"profile-{uuid.uuid4().hex[:8]}"
            
        self._guided_new_analysis_feature_event_profile = dict(config_fields or {})
        self._guided_new_analysis_feature_event_profile["profile_id"] = profile_id
        self._guided_new_analysis_feature_event_profile_status = "applied"
        self._guided_feature_event_editor_dirty = False
        self._guided_new_analysis_feature_event_profile_baseline_source = baseline_path
        self._guided_new_analysis_feature_event_profile_baseline_kind = baseline_kind
        self._guided_new_analysis_feature_event_profile_format = current_format
        self._guided_new_analysis_feature_event_profile_acq_mode = current_acq_mode
        self._guided_new_analysis_feature_event_profile_stale_reasons = []
        self._guided_new_analysis_feature_event_profile_errors = []
        self._guided_new_analysis_feature_event_profile_updated_at_utc = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        
        self._guided_feature_event_status_label.setText(
            GUIDED_DEFAULT_SETTINGS_READY
        )
        self._invalidate_guided_backend_validation(
            "Default feature detection settings were confirmed"
        )
        self._refresh_guided_draft_run_plan_preview()

    def _on_guided_clear_feature_event_profile(self) -> None:
        if getattr(self, "_guided_workflow_mode", "start") == "new_analysis":
            self._on_guided_clear_feature_event_profile_new_analysis()
            return
        run_dir = self._current_guided_completed_run_dir()
        if run_dir:
            profiles_by_run = getattr(self, "_guided_draft_feature_event_profiles_by_run", {})
            profiles_by_run.pop(run_dir, None)
            self._guided_draft_feature_event_profiles_by_run = profiles_by_run
        self._reset_guided_feature_event_editor_to_defaults(
            status_text="Draft feature/event profile cleared from in-memory plan. No files were changed."
        )
        self._guided_feature_event_editor_synced_run = run_dir
        self._refresh_guided_draft_run_plan_preview()

    def _on_guided_clear_feature_event_profile_new_analysis(self) -> None:
        self._invalidate_guided_backend_validation(
            "Default feature detection settings were reset"
        )
        defaults_res = self._active_feature_event_defaults_result()
        baseline_path = defaults_res.baseline_source_path
        baseline_kind = defaults_res.baseline_source_kind
        
        current_format = self._guided_format_combo.currentText() if hasattr(self, "_guided_format_combo") else "auto"
        current_acq_mode = "continuous"
        if hasattr(self, "_guided_acquisition_mode_combo"):
            current_acq_mode = self._guided_acquisition_mode_combo.currentData() or self._guided_acquisition_mode_combo.currentText().lower()
            if not current_acq_mode:
                current_acq_mode = "continuous"

        self._guided_new_analysis_feature_event_profile_stale_reasons = []
        self._guided_new_analysis_feature_event_profile_errors = []
        
        if defaults_res.fallback_reason:
            self._guided_new_analysis_feature_event_profile_status = "unavailable"
            self._guided_new_analysis_feature_event_profile = None
            self._guided_new_analysis_feature_event_profile_baseline_source = baseline_path
            self._guided_new_analysis_feature_event_profile_baseline_kind = baseline_kind
            self._guided_new_analysis_feature_event_profile_format = current_format
            self._guided_new_analysis_feature_event_profile_acq_mode = current_acq_mode
            # Keep the raw loader diagnostic internally; show only the
            # sanitized plain-language message.
            self._guided_new_analysis_feature_event_profile_errors = [defaults_res.fallback_reason]
            self._reset_guided_feature_event_editor_to_defaults(
                status_text=sanitize_guided_default_settings_load_failure(
                    defaults_res.fallback_reason
                )
            )
            self._refresh_guided_draft_run_plan_preview()
            return

        defaults = self._event_feature_defaults_from_active_baseline()
        self._guided_new_analysis_feature_event_profile = dict(defaults)
        self._guided_new_analysis_feature_event_profile_status = "default_initialized"
        self._guided_feature_event_editor_dirty = False
        self._guided_new_analysis_feature_event_profile_baseline_source = baseline_path
        self._guided_new_analysis_feature_event_profile_baseline_kind = baseline_kind
        self._guided_new_analysis_feature_event_profile_format = current_format
        self._guided_new_analysis_feature_event_profile_acq_mode = current_acq_mode
        self._guided_new_analysis_feature_event_profile_updated_at_utc = None
        
        self._set_guided_feature_event_editor_values(
            self._guided_new_analysis_feature_event_profile,
            status_text=GUIDED_DEFAULT_SETTINGS_NOT_CONFIRMED,
        )
        self._refresh_guided_draft_run_plan_preview()

    def _validate_guided_output_path(self, path: str, run_dir: str) -> str | None:
        trimmed = path.strip()
        if not trimmed:
            return "Output root path cannot be empty."

        try:
            from pathlib import Path
            norm_path = Path(trimmed).expanduser().resolve(strict=False)
            norm_run = Path(run_dir).resolve(strict=False)
        except Exception as exc:
            return f"Invalid path format: {exc}"

        if norm_path == norm_run:
            return "Output root cannot be the completed run directory itself."

        if norm_run in norm_path.parents:
            return "Output root cannot be inside the completed run directory."

        legacy_dirs = [
            norm_run / "_analysis",
            norm_run / "_analysis" / "phasic_out",
            norm_run / "_analysis" / "phasic_out" / "features",
            norm_run / "_analysis" / "phasic_out" / "applied_dff",
        ]
        if norm_path in legacy_dirs:
            return "Output root cannot be inside the completed run directory."

        return None

    def _guided_new_analysis_output_policy_context(self) -> dict[str, str]:
        input_path = self._guided_input_dir_edit.text().strip() if hasattr(self, "_guided_input_dir_edit") else ""
        cache_root = ""
        build_request_signature = ""
        record = getattr(self, "_guided_diagnostic_cache_record", None)
        if record is not None:
            cache_root = str(getattr(record, "cache_root_path", "") or "")
            build_request_signature = str(getattr(record, "build_request_signature", "") or "")
        return {
            "input_source_path": input_path,
            "cache_root_path": cache_root,
            "build_request_signature": build_request_signature,
        }

    def _known_guided_new_analysis_protected_roots(self) -> list[str]:
        roots: list[str] = []
        ctx = self._guided_new_analysis_output_policy_context()
        cache_root = ctx.get("cache_root_path", "")
        if cache_root:
            roots.append(cache_root)
            roots.append(os.path.join(cache_root, "_guided_workflow", "previews"))
            roots.append(os.path.join(cache_root, "_guided_workflow", "signal_only_f0_diagnostics"))
            roots.append(os.path.join(cache_root, "_analysis"))
            roots.append(os.path.join(cache_root, "_analysis", "phasic_out"))
            roots.append(os.path.join(cache_root, "_analysis", "phasic_out", "features"))
            roots.append(os.path.join(cache_root, "_analysis", "phasic_out", "applied_dff"))
        run_dir = self._current_guided_completed_run_dir()
        if run_dir:
            roots.append(run_dir)
            roots.append(os.path.join(run_dir, "_analysis"))
            roots.append(os.path.join(run_dir, "_analysis", "phasic_out"))
            roots.append(os.path.join(run_dir, "_analysis", "phasic_out", "features"))
            roots.append(os.path.join(run_dir, "_analysis", "phasic_out", "applied_dff"))
        return [root for root in roots if str(root or "").strip()]

    def _validate_guided_new_analysis_output_policy_path(self, path: str):
        trimmed = str(path or "").strip()
        if not trimmed:
            return validate_output_write_safety(
                source_root="",
                output_base="",
                target_path="",
                operation_kind="production_run",
                allow_existing_target=False,
                overwrite=False,
            )
        ctx = self._guided_new_analysis_output_policy_context()
        source_root = str(ctx.get("input_source_path", "") or "").strip()
        if not source_root:
            return WorkflowValidationResult(
                ok=False,
                code="source_missing",
                message="Raw input/source path is required before applying an output destination.",
            )
        try:
            source_path = Path(source_root).expanduser().resolve(strict=False)
        except Exception as exc:
            return WorkflowValidationResult(
                ok=False,
                code="invalid_source_path",
                message=f"Invalid raw input/source path: {exc}",
            )
        if not source_path.is_dir():
            return WorkflowValidationResult(
                ok=False,
                code="source_invalid",
                message=f"Raw input/source path does not exist or is not a directory: {source_path}.",
            )
        try:
            target = Path(trimmed).expanduser().resolve(strict=False)
        except Exception as exc:
            return WorkflowValidationResult(
                ok=False,
                code="invalid_path",
                message=f"Invalid output destination path: {exc}",
            )
        parent = target.parent
        protected_roots = self._known_guided_new_analysis_protected_roots()
        return validate_output_write_safety(
            source_root=str(source_path),
            output_base=str(parent),
            target_path=str(target),
            operation_kind="production_run",
            allow_existing_target=False,
            overwrite=False,
            protected_roots=protected_roots,
        )

    def _guided_output_policy_for_current_run(self) -> OutputPolicy:
        run_dir = self._current_guided_completed_run_dir()
        if not run_dir:
            return OutputPolicy()
        return getattr(self, "_guided_draft_output_policy_by_run", {}).get(run_dir, OutputPolicy())

    def _guided_new_analysis_output_policy_status_text(self) -> str:
        status = getattr(
            self, "_guided_new_analysis_output_policy_status", "missing"
        )
        if status == "applied":
            return (
                "Output parent folder is configured. Guided Run will create "
                "a new run folder inside it. No directories or files were "
                "created during setup."
            )
        if status == "stale":
            reasons = "; ".join(
                getattr(
                    self,
                    "_guided_new_analysis_output_policy_stale_reasons",
                    [],
                )
                or []
            )
            return (
                "Output folder needs attention before Run: "
                f"{reasons or 'the selected setup changed'}"
            )
        if status == "invalid":
            issues = "; ".join(
                getattr(
                    self,
                    "_guided_new_analysis_output_policy_validation_issues",
                    [],
                )
                or []
            )
            return (
                "Output folder needs attention before Run: "
                f"{issues or 'the selected folder is invalid'}"
            )
        selected_output = (
            self._guided_output_dir_edit.text().strip()
            if hasattr(self, "_guided_output_dir_edit")
            else ""
        )
        if selected_output:
            return (
                "Select data output folder is configured. Required before Run: "
                "choose and apply the run output parent folder in Draft Plan."
            )
        return (
            "Required before Run: choose an output folder in Select data, then "
            "apply the run output parent folder in Draft Plan."
        )

    def _sync_guided_output_policy_editor_to_current_run(self, *, force: bool = False) -> None:
        if getattr(self, "_guided_workflow_mode", "start") == "new_analysis":
            self._sync_guided_output_policy_editor_to_new_analysis(force=force)
            return
        if not hasattr(self, "_guided_output_path_edit"):
            return
        run_dir = self._current_guided_completed_run_dir()
        synced_run = getattr(self, "_guided_output_policy_editor_synced_run", None)
        if not force and run_dir == synced_run:
            return
        policy = getattr(self, "_guided_draft_output_policy_by_run", {}).get(run_dir)
        if policy is not None and policy.output_root:
            with QSignalBlocker(self._guided_output_path_edit):
                self._guided_output_path_edit.setText(policy.output_root)
            self._guided_output_status_label.setText(
                "Showing applied in-memory output policy for this completed run. "
                "No outputs were written."
            )
        else:
            with QSignalBlocker(self._guided_output_path_edit):
                self._guided_output_path_edit.setText("")
            self._guided_output_status_label.setText("No output root is configured.")
        self._guided_output_policy_editor_synced_run = run_dir

    def _sync_guided_output_policy_editor_to_new_analysis(self, *, force: bool = False) -> None:
        if not hasattr(self, "_guided_output_path_edit"):
            return
        self._refresh_guided_new_analysis_output_policy_staleness()
        synced = getattr(self, "_guided_output_policy_editor_synced_run", None)
        path = getattr(self, "_guided_new_analysis_output_policy_path", None)
        if force or synced != "new_analysis":
            with QSignalBlocker(self._guided_output_path_edit):
                self._guided_output_path_edit.setText(str(path or ""))
        self._guided_output_status_label.setText(
            self._guided_new_analysis_output_policy_status_text()
        )
        self._guided_output_policy_editor_synced_run = "new_analysis"

    def _refresh_guided_new_analysis_output_policy_staleness(self) -> None:
        if getattr(self, "_guided_new_analysis_output_policy_status", "missing") not in {"applied", "stale"}:
            return
        path = getattr(self, "_guided_new_analysis_output_policy_path", None)
        if not path:
            return
        ctx = self._guided_new_analysis_output_policy_context()
        stale_reasons: list[str] = []
        if str(getattr(self, "_guided_new_analysis_output_policy_source_path", "") or "") != str(ctx.get("input_source_path", "") or ""):
            stale_reasons.append("input source path changed")
        if str(getattr(self, "_guided_new_analysis_output_policy_cache_root", "") or "") != str(ctx.get("cache_root_path", "") or ""):
            stale_reasons.append("diagnostic cache root changed")
        if str(getattr(self, "_guided_new_analysis_output_policy_build_request_signature", "") or "") != str(ctx.get("build_request_signature", "") or ""):
            stale_reasons.append("diagnostic cache build request changed")
        validation = self._validate_guided_new_analysis_output_policy_path(str(path))
        if not validation.ok:
            reused_own_output_base = (
                validation.code == "target_exists"
                and classify_output_base_reuse_eligibility(path)[0]
            )
            if not reused_own_output_base:
                stale_reasons.append(validation.message)
        if stale_reasons:
            became_stale = (
                getattr(
                    self,
                    "_guided_new_analysis_output_policy_status",
                    "missing",
                )
                != "stale"
            )
            self._guided_new_analysis_output_policy_status = "stale"
            self._guided_new_analysis_output_policy_stale_reasons = list(dict.fromkeys(stale_reasons))
            if became_stale:
                self._invalidate_guided_backend_validation(
                    "output policy became stale"
                )

    def _on_guided_apply_output_policy(self) -> None:
        if getattr(self, "_guided_workflow_mode", "start") == "new_analysis":
            self._on_guided_apply_output_policy_new_analysis()
            return
        run_dir = self._current_guided_completed_run_dir()
        if not run_dir:
            self._guided_output_status_label.setText(
                "Output destination not applied: Open Results must be used first."
            )
            return
        path = self._guided_output_path_edit.text()
        err = self._validate_guided_output_path(path, run_dir)
        if err:
            self._guided_output_status_label.setText(f"Output destination not applied: {err}")
            return

        from pathlib import Path
        resolved_root = str(Path(path.strip()).expanduser().resolve(strict=False))
        policy = OutputPolicy(
            output_root=resolved_root,
            overwrite=False,
            separate_from_source_required=True,
            legacy_outputs_protected=True,
        )

        policies_by_run = getattr(self, "_guided_draft_output_policy_by_run", {})
        previous_policy = policies_by_run.get(run_dir)
        policies_by_run[run_dir] = policy
        self._guided_draft_output_policy_by_run = policies_by_run

        plan, preview_errors = self._build_guided_draft_run_plan()
        errors = list(preview_errors)
        if plan is not None:
            errors.extend(validate_plan_contract(plan))
        if errors:
            if previous_policy is not None:
                policies_by_run[run_dir] = previous_policy
            else:
                policies_by_run.pop(run_dir, None)
            self._guided_draft_output_policy_by_run = policies_by_run
            self._guided_output_status_label.setText(
                "Output destination not applied: " + "; ".join(errors)
            )
            self._refresh_guided_draft_run_plan_preview()
            return

        self._guided_output_status_label.setText(
            "Output destination applied to in-memory draft plan. No directories or files were created."
        )
        self._guided_output_policy_editor_synced_run = run_dir
        self._refresh_guided_draft_run_plan_preview()

    def _on_guided_apply_output_policy_new_analysis(self) -> None:
        path = self._guided_output_path_edit.text()
        validation = self._validate_guided_new_analysis_output_policy_path(path)
        if not validation.ok:
            self._guided_new_analysis_output_policy_status = "invalid"
            self._guided_new_analysis_output_policy_validation_issues = [validation.message]
            self._guided_new_analysis_output_policy_stale_reasons = []
            self._guided_new_analysis_output_policy_explicitly_applied = False
            self._guided_output_status_label.setText(
                self._guided_new_analysis_output_policy_status_text()
            )
            self._refresh_guided_draft_run_plan_preview()
            return
        resolved_root = str(Path(path.strip()).expanduser().resolve(strict=False))
        ctx = self._guided_new_analysis_output_policy_context()
        self._guided_new_analysis_output_policy_status = "applied"
        self._guided_new_analysis_output_policy_path = resolved_root
        self._guided_new_analysis_output_policy_validation_issues = []
        self._guided_new_analysis_output_policy_stale_reasons = []
        self._guided_new_analysis_output_policy_updated_at_utc = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        self._guided_new_analysis_output_policy_explicitly_applied = True
        self._guided_new_analysis_output_policy_source_path = ctx.get("input_source_path", "")
        self._guided_new_analysis_output_policy_cache_root = ctx.get("cache_root_path", "")
        self._guided_new_analysis_output_policy_build_request_signature = ctx.get("build_request_signature", "")
        self._guided_output_status_label.setText(
            self._guided_new_analysis_output_policy_status_text()
        )
        self._invalidate_guided_backend_validation("output policy applied")
        self._guided_output_policy_editor_synced_run = "new_analysis"
        self._refresh_guided_draft_run_plan_preview()

    def _on_guided_clear_output_policy(self) -> None:
        if getattr(self, "_guided_workflow_mode", "start") == "new_analysis":
            self._on_guided_clear_output_policy_new_analysis()
            return
        run_dir = self._current_guided_completed_run_dir()
        if run_dir:
            policies_by_run = getattr(self, "_guided_draft_output_policy_by_run", {})
            policies_by_run.pop(run_dir, None)
            self._guided_draft_output_policy_by_run = policies_by_run

        with QSignalBlocker(self._guided_output_path_edit):
            self._guided_output_path_edit.setText("")
        self._guided_output_status_label.setText(
            "Draft output destination cleared from in-memory plan. No files were changed."
        )
        self._guided_output_policy_editor_synced_run = run_dir
        self._refresh_guided_draft_run_plan_preview()

    def _on_guided_clear_output_policy_new_analysis(self) -> None:
        self._invalidate_guided_backend_validation("output policy cleared")
        self._guided_new_analysis_output_policy_status = "missing"
        self._guided_new_analysis_output_policy_path = None
        self._guided_new_analysis_output_policy_validation_issues = []
        self._guided_new_analysis_output_policy_stale_reasons = []
        self._guided_new_analysis_output_policy_updated_at_utc = None
        self._guided_new_analysis_output_policy_explicitly_applied = False
        self._guided_new_analysis_output_policy_source_path = None
        self._guided_new_analysis_output_policy_cache_root = None
        self._guided_new_analysis_output_policy_build_request_signature = None
        with QSignalBlocker(self._guided_output_path_edit):
            self._guided_output_path_edit.setText("")
        self._guided_output_status_label.setText(
            self._guided_new_analysis_output_policy_status_text()
        )
        self._guided_output_policy_editor_synced_run = "new_analysis"
        self._refresh_guided_draft_run_plan_preview()

