    def _reset_guided_imported_plan_review_display(self, message: str = "No exported plan opened for review.") -> None:
        self._guided_imported_plan_candidate = None
        self._guided_imported_plan_file_path = ""
        self._guided_imported_plan_status = ""
        self._guided_imported_plan_review_run_dir = self._current_guided_completed_run_dir()
        self._guided_imported_plan_adoption_status = self._no_guided_imported_plan_adoption_status()
        status = getattr(self, "_guided_imported_plan_status_label", None)
        summary = getattr(self, "_guided_imported_plan_summary_label", None)
        adoption = getattr(self, "_guided_imported_plan_adoption_status_label", None)
        if status is not None:
            status.setText(message)
        if summary is not None:
            summary.setText("Candidate review: none.\nAdoption: unavailable in this read-only stage\nExecution: blocked\nFiles written: none")
        if adoption is not None:
            adoption.setText(
                self._guided_imported_plan_adoption_status_text(
                    self._guided_imported_plan_adoption_status
                )
            )
        self._refresh_guided_imported_plan_review_visibility()

    def _show_guided_imported_plan_open_failed(self, reason: str) -> None:
        self._reset_guided_imported_plan_review_display()
        status = getattr(self, "_guided_imported_plan_status_label", None)
        if status is not None:
            status.setText(f"Open plan failed: {reason}")

    def _no_guided_imported_plan_adoption_status(self) -> dict[str, object]:
        return {
            "eligible": False,
            "blocking_reasons": ["no active candidate"],
            "warnings": [],
            "source_status": "not checked: no candidate plan is open for review",
            "roi_status": "not checked: no candidate plan is open for review",
            "correction_strategy_status": "not checked: no candidate plan is open for review",
            "feature_event_status": "not checked: no candidate plan is open for review",
            "output_policy_status": "not checked: no candidate plan is open for review",
            "adoption_action": "unavailable in this stage",
            "execution_status": "blocked",
            "files_written": "none",
        }

    def _guided_imported_plan_adoption_status_text(self, status: dict[str, object] | None) -> str:
        status = status or self._no_guided_imported_plan_adoption_status()
        blockers = [str(item) for item in status.get("blocking_reasons", [])]
        warnings = [str(item) for item in status.get("warnings", [])]
        lines = [
            "Future adoption eligibility",
            "Eligibility is informational only. No adoption action is available in this stage.",
            f"Future adoption eligible: {'Yes' if status.get('eligible') else 'No'}",
            f"Adoption action: {status.get('adoption_action', 'unavailable in this stage')}",
            "Blocking reasons:",
        ]
        lines.extend([f"- {item}" for item in blockers] if blockers else ["- none"])
        lines.append("Warnings:")
        lines.extend([f"- {item}" for item in warnings] if warnings else ["- none"])
        lines.extend(
            [
                f"Source: {status.get('source_status', '')}",
                f"ROI: {status.get('roi_status', '')}",
                f"Correction strategies: {status.get('correction_strategy_status', '')}",
                f"Feature/event profile: {status.get('feature_event_status', '')}",
                f"Output policy: {status.get('output_policy_status', '')}",
                f"Execution: {status.get('execution_status', 'blocked')}",
                f"Files written: {status.get('files_written', 'none')}",
            ]
        )
        return "\n".join(lines)

    def _clear_guided_imported_plan_candidate_if_run_changed(self) -> None:
        if getattr(self, "_guided_imported_plan_candidate", None) is None:
            return
        current_run = self._current_guided_completed_run_dir()
        review_run = getattr(self, "_guided_imported_plan_review_run_dir", None)
        if current_run != review_run:
            self._reset_guided_imported_plan_review_display(
                "Candidate plan review cleared because the loaded completed run changed."
            )

    def _resolve_guided_import_review_path(self, path: str) -> tuple[Path | None, str | None]:
        trimmed = str(path or "").strip()
        if not trimmed:
            return None, "Path cannot be empty."
        if not trimmed.lower().endswith(".json"):
            return None, "Plan file must have .json extension."
        try:
            review_path = Path(trimmed).expanduser().resolve(strict=False)
        except Exception as exc:
            return None, f"Invalid path format: {exc}"
        if not review_path.parent.exists():
            return None, "Parent directory does not exist."
        if not review_path.exists():
            return None, f"File does not exist at {review_path}."
        if review_path.is_dir():
            return None, "Path points to a directory, not a file."
        return review_path, None

    def _json_max_depth(self, value: object, depth: int = 0) -> int:
        if isinstance(value, dict):
            if not value:
                return depth + 1
            return max(self._json_max_depth(item, depth + 1) for item in value.values())
        if isinstance(value, list):
            if not value:
                return depth + 1
            return max(self._json_max_depth(item, depth + 1) for item in value)
        return depth

    def _reject_duplicate_json_keys(self, pairs: list[tuple[str, object]]) -> dict[str, object]:
        result: dict[str, object] = {}
        for key, value in pairs:
            if key in result:
                raise ValueError(f"duplicate JSON key: {key}")
            result[key] = value
        return result

    def _read_guided_import_review_json(self, path: Path) -> tuple[dict[str, object] | None, str | None]:
        try:
            if path.stat().st_size > 500 * 1024:
                return None, "File exceeds maximum size limit (500 KB)."
            text = path.read_text(encoding="utf-8")
        except PermissionError:
            return None, "File cannot be read (Permission denied)."
        except OSError as exc:
            return None, f"File cannot be read ({exc})."
        try:
            payload = json.loads(text, object_pairs_hook=self._reject_duplicate_json_keys)
        except json.JSONDecodeError as exc:
            return None, f"Invalid JSON format. {exc}"
        except ValueError as exc:
            return None, str(exc)
        if not isinstance(payload, dict):
            return None, "JSON root must be an object."
        if self._json_max_depth(payload) > 10:
            return None, "JSON nesting depth exceeds maximum supported depth (10)."
        if "schema_version" not in payload:
            return None, "Missing plan schema version."
        if not isinstance(payload.get("schema_version"), str):
            return None, "schema_version must be a string."
        schema = str(payload.get("schema_version") or "")
        if schema != SCHEMA_VERSION:
            return None, f"Unsupported schema version '{schema}'."
        return payload, None

    def _on_guided_open_plan_for_review(self) -> None:
        path_text = self._guided_imported_plan_path_edit.text()
        review_path, path_error = self._resolve_guided_import_review_path(path_text)
        if path_error:
            self._show_guided_imported_plan_open_failed(path_error)
            return

        payload, read_error = self._read_guided_import_review_json(review_path)
        if read_error:
            self._show_guided_imported_plan_open_failed(read_error)
            return

        try:
            candidate = deserialize_plan_from_dict(payload)
        except GuidedRunPlanContractError as exc:
            self._show_guided_imported_plan_open_failed(
                f"Plan contract deserialization failed: {exc}"
            )
            return
        except Exception as exc:
            self._show_guided_imported_plan_open_failed(f"Unexpected review error: {exc}")
            return

        try:
            contract_errors = validate_plan_contract(candidate)
            review = self._guided_imported_plan_review(candidate, review_path, contract_errors)
            adoption_status = self._guided_imported_plan_adoption_eligibility(
                candidate,
                contract_errors,
            )
        except Exception as exc:
            self._show_guided_imported_plan_open_failed(f"Unexpected review error: {exc}")
            return
        self._guided_imported_plan_candidate = candidate
        self._guided_imported_plan_file_path = str(review_path)
        self._guided_imported_plan_status = str(review.get("contract_status") or "")
        self._guided_imported_plan_review_run_dir = self._current_guided_completed_run_dir()
        self._guided_imported_plan_adoption_status = adoption_status
        self._guided_imported_plan_status_label.setText(
            "Plan opened for read-only review. Live draft plan was not changed."
        )
        self._guided_imported_plan_summary_label.setText(
            self._guided_imported_plan_review_summary_text(review)
        )
        adoption_label = getattr(self, "_guided_imported_plan_adoption_status_label", None)
        if adoption_label is not None:
            adoption_label.setText(self._guided_imported_plan_adoption_status_text(adoption_status))
        self._refresh_guided_imported_plan_review_visibility()

    def _guided_completed_run_basic_validity(self, run_dir: str) -> str:
        if not run_dir:
            return "no imported completed-run source path"
        if not os.path.exists(run_dir):
            return "imported source path missing"
        if not os.path.isdir(run_dir):
            return "imported source path is not a directory"
        completed, evidence = is_successful_completed_run_dir(run_dir)
        if not completed:
            return f"source exists but is not a confirmed completed run ({evidence})"
        source = resolve_completed_run_preview_source(run_dir)
        if not source.ok:
            return f"basic source artifact check failed ({source.reason})"
        return "valid completed-run source by basic artifact check"

    def _guided_completed_run_roi_inventory(self, run_dir: str) -> tuple[list[str], list[int], str]:
        if not run_dir:
            return [], [], "ROI compatibility unknown: no active completed run loaded"
        source = resolve_completed_run_preview_source(run_dir)
        if not source.ok:
            return [], [], f"ROI compatibility unknown: {source.reason}"
        try:
            with open_phasic_cache(source.phasic_trace_cache_path) as cache:
                rois = [str(roi) for roi in list_cache_rois(cache)]
                chunks = [int(chunk) for chunk in list_cache_chunk_ids(cache)]
        except Exception as exc:
            return [], [], f"ROI compatibility unknown: unable to read completed-run cache ({exc})"
        return rois, chunks, "ROI inventory read from active completed-run cache"

    def _is_path_equal_or_inside(self, path: Path, root: Path) -> bool:
        return path == root or root in path.parents

    def _guided_output_policy_review_lines(self, plan: GuidedRunPlan) -> tuple[str, list[str]]:
        policy = plan.output_policy or OutputPolicy()
        warnings: list[str] = []
        if not policy.output_root:
            status = "no output destination configured"
        else:
            status = f"output root: {policy.output_root}"
            try:
                output_root = Path(str(policy.output_root)).expanduser().resolve(strict=False)
                source_paths = [
                    str(plan.source.completed_run_dir or "").strip(),
                    self._current_guided_completed_run_dir(),
                ]
                for source_path in source_paths:
                    if not source_path:
                        continue
                    source_root = Path(source_path).expanduser().resolve(strict=False)
                    if self._is_path_equal_or_inside(output_root, source_root):
                        warnings.append(f"output root is equal to or inside source: {source_root}")
                    legacy_roots = [
                        source_root / "_analysis",
                        source_root / "_analysis" / "phasic_out",
                        source_root / "_analysis" / "phasic_out" / "features",
                        source_root / "_analysis" / "phasic_out" / "applied_dff",
                    ]
                    for legacy_root in legacy_roots:
                        if self._is_path_equal_or_inside(output_root, legacy_root):
                            warnings.append(f"output root is inside legacy output directory: {legacy_root}")
                            break
            except Exception as exc:
                warnings.append(f"output root path could not be normalized: {exc}")
        if policy.overwrite:
            warnings.append("Safety warning: Overwrite is enabled.")
        if not policy.separate_from_source_required:
            warnings.append("Safety warning: separate_from_source_required is disabled.")
        if not policy.legacy_outputs_protected:
            warnings.append("Safety warning: legacy_outputs_protected is disabled.")
        return status, warnings

    def _source_validity_passed(self, status: str) -> bool:
        return str(status or "").startswith("valid completed-run source")

    def _guided_imported_plan_adoption_eligibility(
        self,
        plan: GuidedRunPlan | None,
        contract_errors: list[str] | None = None,
    ) -> dict[str, object]:
        if plan is None:
            return self._no_guided_imported_plan_adoption_status()

        blockers: list[str] = []
        warnings: list[str] = []
        errors = list(contract_errors if contract_errors is not None else validate_plan_contract(plan))

        if plan.schema_version != SCHEMA_VERSION:
            blockers.append(f"unsupported schema version: {plan.schema_version}")
        if plan.mode != "completed_run_planning":
            blockers.append(f"candidate mode is not completed_run_planning: {plan.mode}")
        for error in errors:
            blockers.append(f"contract error: {error}")

        current_source = self._current_guided_completed_run_dir()
        imported_source = str(plan.source.completed_run_dir or "").strip()
        imported_resolved = os.path.realpath(imported_source) if imported_source else ""
        current_resolved = os.path.realpath(current_source) if current_source else ""
        source_status_parts: list[str] = []
        if not current_resolved:
            blockers.append("no current completed run loaded")
            source_status_parts.append("blocked: no current completed run loaded")
        if not imported_resolved:
            blockers.append("imported source is empty")
            source_status_parts.append("blocked: imported source is empty")
        if current_resolved and imported_resolved:
            if imported_resolved != current_resolved:
                blockers.append("source mismatch between imported plan and current completed run")
                source_status_parts.append("blocked: source mismatch")
            else:
                source_status_parts.append("source matched")

        if current_resolved:
            current_validity = self._guided_completed_run_basic_validity(current_resolved)
            if not self._source_validity_passed(current_validity):
                blockers.append(f"current completed-run source invalid: {current_validity}")
            source_status_parts.append(f"current source: {current_validity}")
        if imported_resolved:
            imported_validity = self._guided_completed_run_basic_validity(imported_resolved)
            if not self._source_validity_passed(imported_validity):
                blockers.append(f"imported source invalid: {imported_validity}")
            source_status_parts.append(f"imported source: {imported_validity}")
        source_status = "; ".join(source_status_parts) if source_status_parts else "not checked"

        current_rois: list[str] = []
        current_chunks: list[int] = []
        roi_status_parts: list[str] = []
        if current_resolved:
            current_rois, current_chunks, inventory_status = self._guided_completed_run_roi_inventory(current_resolved)
            if not current_rois:
                blockers.append(f"ROI inventory unavailable: {inventory_status}")
                roi_status_parts.append(f"blocked: {inventory_status}")
            else:
                roi_status_parts.append(f"current ROI inventory: {len(current_rois)} ROI(s)")
        else:
            roi_status_parts.append("blocked: no current completed run loaded")

        imported_rois = [str(entry.roi or "").strip() for entry in plan.roi_plan if str(entry.roi or "").strip()]
        if not imported_rois:
            blockers.append("zero ROI choices cannot be adopted in first adoption implementation")
            roi_status_parts.append("blocked: zero ROI choices")
        duplicate_rois = sorted({roi for roi in imported_rois if imported_rois.count(roi) > 1})
        if duplicate_rois:
            blockers.append("duplicate imported ROI entries: " + ", ".join(duplicate_rois))
        if current_rois and imported_rois:
            missing_rois = sorted(roi for roi in imported_rois if roi not in current_rois)
            extra_rois = sorted(roi for roi in current_rois if roi not in imported_rois)
            if missing_rois:
                blockers.append("missing imported ROI(s) in current run: " + ", ".join(missing_rois))
                roi_status_parts.append("blocked: missing imported ROI(s)")
            else:
                roi_status_parts.append("imported ROI choices match current inventory")
            if extra_rois:
                warnings.append("extra current ROI(s) not present in candidate; adopted draft would be partial: " + ", ".join(extra_rois))
        if current_chunks:
            chunk_set = set(current_chunks)
            stale_chunks: list[str] = []
            for entry in plan.roi_plan:
                for evidence in entry.evidence:
                    if evidence.chunk_id not in chunk_set:
                        stale_chunks.append(f"{entry.roi}: chunk {evidence.chunk_id}")
                    if evidence.stale:
                        stale_chunks.append(f"{entry.roi}: chunk {evidence.chunk_id} marked stale")
            if stale_chunks:
                warnings.append("evidence chunk availability/staleness warning: " + "; ".join(stale_chunks))
        elif imported_rois:
            warnings.append("evidence chunk availability not checked because current chunk inventory is unavailable")
        roi_status = "; ".join(roi_status_parts) if roi_status_parts else "not checked"

        strategy_status_parts: list[str] = []
        if not plan.roi_plan:
            strategy_status_parts.append("blocked: no ROI plan entries")
        for entry in plan.roi_plan:
            choice = entry.correction_strategy
            roi = str(entry.roi or "(missing ROI)")
            if choice is None:
                blockers.append(f"ROI {roi} has no correction strategy")
                continue
            try:
                validate_correction_strategy(choice.strategy)
            except GuidedRunPlanContractError as exc:
                blockers.append(f"ROI {roi} correction strategy blocked: {exc}")
                continue
            if choice.strategy == "signal_only_f0":
                warnings.append(f"ROI {roi}: Signal-Only F0 is explicit, not fallback; no diagnostic will run")
        configured_strategy_count = len([entry for entry in plan.roi_plan if entry.correction_strategy is not None])
        strategy_status_parts.append(f"{configured_strategy_count} ROI strategy choice(s) configured")
        correction_strategy_status = "; ".join(strategy_status_parts)

        if not plan.feature_event_profiles:
            feature_event_status = "no feature/event profile configured"
            warnings.append("no feature/event profile; candidate would remain incomplete")
        else:
            feature_event_status = f"{len(plan.feature_event_profiles)} feature/event profile(s)"
            if len(plan.feature_event_profiles) > 1:
                warnings.append("multiple feature/event profiles would be preserved as planning state")
            for index, profile in enumerate(plan.feature_event_profiles):
                if profile.scope == "chunk":
                    blockers.append(f"feature/event profile {index} uses chunk scope")

        output_policy_status, output_policy_warnings = self._guided_output_policy_review_lines(plan)
        policy = plan.output_policy or OutputPolicy()
        if not policy.output_root:
            warnings.append("no output_root; candidate would remain incomplete")
        for warning in output_policy_warnings:
            blockers.append(f"unsafe OutputPolicy: {warning}")

        return {
            "eligible": not blockers,
            "blocking_reasons": blockers,
            "warnings": warnings,
            "source_status": source_status,
            "roi_status": roi_status,
            "correction_strategy_status": correction_strategy_status,
            "feature_event_status": feature_event_status,
            "output_policy_status": output_policy_status,
            "adoption_action": "unavailable in this stage",
            "execution_status": "blocked",
            "files_written": "none",
        }

    def _guided_imported_plan_review(
        self,
        plan: GuidedRunPlan,
        file_path: Path,
        contract_errors: list[str],
    ) -> dict[str, object]:
        imported_source = str(plan.source.completed_run_dir or "")
        imported_resolved = os.path.realpath(imported_source) if imported_source else ""
        current_source = self._current_guided_completed_run_dir()
        current_resolved = os.path.realpath(current_source) if current_source else ""

        if not current_resolved:
            source_match_status = "not matched: no active completed run loaded"
        elif not imported_resolved:
            source_match_status = "not matched: imported source missing"
        elif imported_resolved == current_resolved:
            source_match_status = "source matched"
        else:
            source_match_status = "source mismatch"

        source_validity = self._guided_completed_run_basic_validity(imported_resolved)
        current_rois, current_chunks, roi_inventory_status = self._guided_completed_run_roi_inventory(current_resolved)
        imported_rois = [str(entry.roi) for entry in plan.roi_plan if str(entry.roi or "").strip()]
        missing_imported = sorted(roi for roi in imported_rois if current_rois and roi not in current_rois)
        extra_current = sorted(roi for roi in current_rois if roi not in imported_rois)
        if not current_resolved:
            roi_status = "unknown: no active completed run loaded"
        elif not current_rois:
            roi_status = roi_inventory_status
        elif not imported_rois:
            roi_status = "incomplete: zero imported ROI choices"
        elif missing_imported:
            roi_status = "missing imported ROIs"
        elif extra_current:
            roi_status = "compatible partial: active run has extra ROIs"
        else:
            roi_status = "compatible"

        evidence_warnings: list[str] = []
        if current_chunks:
            chunk_set = set(current_chunks)
            for entry in plan.roi_plan:
                for evidence in entry.evidence:
                    if evidence.chunk_id not in chunk_set:
                        evidence_warnings.append(
                            f"ROI {entry.roi} evidence chunk {evidence.chunk_id} is not in active chunk inventory"
                        )
        else:
            evidence_warnings.append("evidence chunk availability not checked in 4H1")

        strategy_lines: list[str] = []
        for entry in plan.roi_plan:
            choice = entry.correction_strategy
            if choice is None:
                strategy_lines.append(f"{entry.roi}: no correction strategy marked")
                continue
            label = str(choice.strategy_label or choice.strategy)
            if choice.strategy == "signal_only_f0":
                label = "Signal-Only F0 (explicit user mark; not fallback)"
            strategy_lines.append(f"{entry.roi}: {label} [{choice.strategy}]")
        if not strategy_lines:
            strategy_lines.append("none")

        feature_lines = feature_event_profile_summary_lines(plan)
        output_status, output_warnings = self._guided_output_policy_review_lines(plan)
        contract_status = "valid" if not contract_errors else f"invalid ({len(contract_errors)} contract error(s))"
        completeness_status = "incomplete" if (
            not plan.roi_plan or not plan.feature_event_profiles or not plan.output_policy.output_root
        ) else "configured"

        return {
            "file_path": str(file_path),
            "parse_status": "success",
            "schema_status": plan.schema_version,
            "contract_status": contract_status,
            "completeness_status": completeness_status,
            "contract_errors": list(contract_errors),
            "plan_id": plan.plan_id or "(none)",
            "plan_mode": plan.mode,
            "imported_source_path": imported_source or "(none)",
            "imported_source_resolved_path": imported_resolved or "(none)",
            "current_source_path": current_source or "(none)",
            "current_source_resolved_path": current_resolved or "(none)",
            "source_match_status": source_match_status,
            "source_validity_status": source_validity,
            "roi_status": roi_status,
            "missing_imported_rois": missing_imported,
            "extra_current_rois": extra_current,
            "evidence_warnings": evidence_warnings,
            "correction_strategy_status": f"{len(plan.roi_plan)} ROI plan entr{'y' if len(plan.roi_plan) == 1 else 'ies'}",
            "correction_strategy_lines": strategy_lines,
            "feature_event_status": f"{len(plan.feature_event_profiles)} profile(s)",
            "feature_event_lines": feature_lines,
            "output_policy_status": output_status,
            "output_policy_warnings": output_warnings,
            "adoption_status": "unavailable in this read-only stage",
            "execution_status": "blocked: execution intentionally unavailable",
            "files_written": "none",
        }

    def _guided_imported_plan_review_summary_text(self, review: dict[str, object]) -> str:
        lines = [
            f"File: {review['file_path']}",
            f"Parse: {review['parse_status']}",
            f"Schema: {review['schema_status']}",
            f"Contract: {review['contract_status']}",
            f"Completeness: {review['completeness_status']}",
            f"Plan ID: {review['plan_id']}",
            f"Plan mode: {review['plan_mode']}",
            f"Imported source: {review['imported_source_path']}",
            f"Imported source resolved: {review['imported_source_resolved_path']}",
            f"Current source: {review['current_source_path']}",
            f"Current source resolved: {review['current_source_resolved_path']}",
            f"Source: {review['source_match_status']}",
            f"Source validity: {review['source_validity_status']}",
            f"ROI compatibility: {review['roi_status']}",
        ]
        missing = review.get("missing_imported_rois") or []
        extra = review.get("extra_current_rois") or []
        if missing:
            lines.append("Missing imported ROIs: " + ", ".join(str(item) for item in missing))
        if extra:
            lines.append("Extra current ROIs: " + ", ".join(str(item) for item in extra))
        evidence = review.get("evidence_warnings") or []
        if evidence:
            lines.append("Evidence warnings: " + "; ".join(str(item) for item in evidence))

        lines.append(f"Correction strategies: {review['correction_strategy_status']}")
        for line in review.get("correction_strategy_lines") or []:
            lines.append(f"- {line}")

        lines.append(f"Feature/event profiles: {review['feature_event_status']}")
        for line in review.get("feature_event_lines") or []:
            lines.append(f"- {line}")

        lines.append(f"Output policy: {review['output_policy_status']}")
        output_warnings = review.get("output_policy_warnings") or []
        if output_warnings:
            lines.append("Output policy warnings: " + "; ".join(str(item) for item in output_warnings))

        errors = review.get("contract_errors") or []
        if errors:
            lines.append("Contract errors:")
            lines.extend(f"- {err}" for err in errors)
        lines.extend(
            [
                f"Adoption: {review['adoption_status']}",
                f"Execution: {review['execution_status']}",
                f"Files written: {review['files_written']}",
            ]
        )
        return "\n".join(str(line) for line in lines)

    def _lock_main_splitter_handle(self) -> None:
        """Keep shell widths mode-controlled; divider is not user-adjustable."""
        splitter = getattr(self, "_main_splitter", None)
        if splitter is None or splitter.count() < 2:
            return
        handle = splitter.handle(1)
        if handle is None:
            return
        handle.setEnabled(False)
        handle.setFocusPolicy(Qt.NoFocus)
        handle.setCursor(Qt.ArrowCursor)
        handle.setAttribute(Qt.WA_TransparentForMouseEvents, True)

    def _splitter_total_width(self) -> int:
        splitter = getattr(self, "_main_splitter", None)
        if splitter is None:
            return 0
        total = splitter.width()
        if total > 0:
            return total
        total = sum(splitter.sizes())
        if total > 0:
            return total
        return max(self.width() - 24, 1100)

    def _target_splitter_left_width(self, *, setup_mode: bool) -> int:
        left_pane = getattr(self, "_left_pane", None)
        if left_pane is None:
            return 0
        total = self._splitter_total_width()
        left_floor = left_pane.minimumWidth()
        if setup_mode:
            left = max(
                int(total * self._shell_setup_left_ratio),
                self._shell_setup_left_min,
                left_floor,
            )
            right_floor = self._shell_setup_right_min
        else:
            left = max(int(total * self._shell_workspace_left_ratio), left_floor)
            right_floor = self._shell_workspace_right_min
        left = min(left, left_pane.maximumWidth())
        max_left_for_right_floor = total - right_floor
        if max_left_for_right_floor >= left_floor:
            left = min(left, max_left_for_right_floor)
        return left

    def _set_shell_left_floor(self, *, setup_mode: bool) -> None:
        left_pane = getattr(self, "_left_pane", None)
        if left_pane is None:
            return
        floor = self._shell_left_width_floor if setup_mode else self._shell_workspace_left_floor
        if left_pane.minimumWidth() != floor:
            left_pane.setMinimumWidth(floor)

    def _record_splitter_nonzero_sizes(self) -> None:
        splitter = getattr(self, "_main_splitter", None)
        if splitter is None:
            return
        sizes = splitter.sizes()
        if len(sizes) < 2:
            return
        left = int(sizes[0])
        right = int(sizes[1])
        if left > 0:
            self._left_pane_last_nonzero_width = left
        if right > 0:
            self._right_pane_last_nonzero_width = right

    def _clamp_left_width_for_mode(self, left: int, *, setup_mode: bool, total: int) -> int:
        left_pane = getattr(self, "_left_pane", None)
        if left_pane is None:
            return max(0, min(int(left), int(total)))
        left_floor = left_pane.minimumWidth()
        clamped = max(int(left), left_floor)
        clamped = min(clamped, left_pane.maximumWidth())
        right_floor = self._shell_setup_right_min if setup_mode else self._shell_workspace_right_min
        max_left_for_right_floor = total - right_floor
        if max_left_for_right_floor >= left_floor:
            clamped = min(clamped, max_left_for_right_floor)
        return max(0, min(clamped, int(total)))

    def _refresh_pane_toggle_buttons(self) -> None:
        if hasattr(self, "_left_pane_toggle_btn"):
            self._left_pane_toggle_btn.setText(
                "Show Workflow" if self._left_pane_collapsed else "Hide Workflow"
            )
        if hasattr(self, "_right_pane_toggle_btn"):
            self._right_pane_toggle_btn.setText(
                "Show Results" if self._right_pane_collapsed else "Hide Results"
            )

    def _apply_splitter_mode(self, *, setup_mode: bool) -> None:
        splitter = getattr(self, "_main_splitter", None)
        left_pane = getattr(self, "_left_pane", None)
        if splitter is None or left_pane is None:
            return

        if self._left_pane_collapsed and self._right_pane_collapsed:
            # Keep at least one pane visible.
            self._right_pane_collapsed = False

        total = self._splitter_total_width()
        if total <= 0:
            return

        if self._left_pane_collapsed:
            if left_pane.minimumWidth() != 0:
                left_pane.setMinimumWidth(0)
            left = 0
            right = max(1, total)
            self._pending_left_restore_width = None
            self._splitter_restore_reapply_passes = 0
        else:
            self._set_shell_left_floor(setup_mode=setup_mode)
            if self._right_pane_collapsed:
                preferred_left = self._pending_left_restore_width
                if preferred_left is None or int(preferred_left) <= 0:
                    preferred_left = self._left_pane_last_nonzero_width
                if int(preferred_left) <= 0:
                    preferred_left = self._target_splitter_left_width(setup_mode=setup_mode)
                left = max(1, min(int(preferred_left), int(total)))
                right = 0
                self._splitter_restore_reapply_passes = 0
            else:
                if (
                    self._pending_left_restore_width is not None
                    or self._pending_right_restore_width is not None
                ):
                    left = self._target_splitter_left_width(setup_mode=setup_mode)
                    if (
                        self._pending_left_restore_width is not None
                        and self._pending_right_restore_width is not None
                    ):
                        left_pref = float(max(0, int(self._pending_left_restore_width)))
                        right_pref = float(max(0, int(self._pending_right_restore_width)))
                        total_pref = left_pref + right_pref
                        if total_pref > 0:
                            left = int(total * (left_pref / total_pref))
                    elif self._pending_left_restore_width is not None:
                        left = int(self._pending_left_restore_width)
                    elif self._pending_right_restore_width is not None:
                        left = int(total) - int(self._pending_right_restore_width)
                    left = self._clamp_left_width_for_mode(
                        left, setup_mode=setup_mode, total=total
                    )
                    # _refresh_splitter_workspace_policy applies twice; hold restored
                    # widths for one additional pass so restore does not get overwritten.
                    self._splitter_restore_reapply_passes = 1
                elif self._splitter_restore_reapply_passes > 0:
                    pref_total = (
                        max(0, int(self._left_pane_last_nonzero_width))
                        + max(0, int(self._right_pane_last_nonzero_width))
                    )
                    if pref_total > 0:
                        left = int(
                            total
                            * (max(0, int(self._left_pane_last_nonzero_width)) / pref_total)
                        )
                        left = self._clamp_left_width_for_mode(
                            left, setup_mode=setup_mode, total=total
                        )
                    else:
                        left = self._target_splitter_left_width(setup_mode=setup_mode)
                    self._splitter_restore_reapply_passes -= 1
                else:
                    left = self._target_splitter_left_width(setup_mode=setup_mode)
                right = max(1, int(total) - int(left))
            self._pending_left_restore_width = None

        self._pending_right_restore_width = None
        splitter.setSizes([int(left), int(right)])
        self._record_splitter_nonzero_sizes()
        self._refresh_pane_toggle_buttons()

    def _toggle_left_pane_collapsed(self) -> None:
        self._record_splitter_nonzero_sizes()
        if self._left_pane_collapsed:
            self._left_pane_collapsed = False
            self._pending_left_restore_width = max(1, int(self._left_pane_last_nonzero_width))
        else:
            if self._right_pane_collapsed:
                self._right_pane_collapsed = False
                self._pending_right_restore_width = max(
                    1, int(self._right_pane_last_nonzero_width)
                )
            self._left_pane_collapsed = True
            self._pending_left_restore_width = None
        self._refresh_splitter_workspace_policy()

    def _toggle_right_pane_collapsed(self) -> None:
        self._record_splitter_nonzero_sizes()
        if self._right_pane_collapsed:
            self._right_pane_collapsed = False
            self._pending_right_restore_width = max(
                1, int(self._right_pane_last_nonzero_width)
            )
        else:
            if self._left_pane_collapsed:
                self._left_pane_collapsed = False
                self._pending_left_restore_width = max(
                    1, int(self._left_pane_last_nonzero_width)
                )
            self._right_pane_collapsed = True
            self._pending_right_restore_width = None
        self._refresh_splitter_workspace_policy()

    def _apply_splitter_setup_mode(self) -> None:
        self._apply_splitter_mode(setup_mode=True)

    def _apply_splitter_workspace_mode(self) -> None:
        self._apply_splitter_mode(setup_mode=False)

    def _is_workspace_splitter_mode(self) -> bool:
        if self._is_complete_workspace_active:
            return True
        if self._validation_passed:
            return True
        if self._ui_state in (RunnerState.RUNNING, RunnerState.VALIDATING):
            return True
        if self._runner.is_running():
            return True
        return False

    def _apply_splitter_workspace_policy(self) -> None:
        if self._is_workspace_splitter_mode():
            self._apply_splitter_workspace_mode()
        else:
            self._apply_splitter_setup_mode()

    def _refresh_splitter_workspace_policy(self) -> None:
        self._apply_splitter_workspace_policy()
        if hasattr(self, "_main_splitter"):
            QTimer.singleShot(0, self._apply_splitter_workspace_policy)

    def _build_left_pane(self) -> QWidget:
        """Fixed left column with control area above and log pane below."""
        pane = QWidget()
        pane.setObjectName("workflowColumn")
        layout = QVBoxLayout(pane)
        self._left_pane_layout = layout
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(10)

        workflow_title = QLabel("Workflow Setup")
        workflow_title.setObjectName("workflowColumnTitle")
        layout.addWidget(workflow_title)

        workflow_subtitle = QLabel(
            "Configure inputs, validate settings, and launch runs from top to bottom."
        )
        workflow_subtitle.setWordWrap(True)
        workflow_subtitle.setObjectName("workflowColumnSubtitle")
        layout.addWidget(workflow_subtitle)

        controls_scroll = QScrollArea()
        controls_scroll.setWidgetResizable(True)
        controls_scroll.setFrameShape(QScrollArea.NoFrame)
        controls_scroll.setHorizontalScrollBarPolicy(Qt.ScrollBarAlwaysOff)
        controls_scroll.setVerticalScrollBarPolicy(Qt.ScrollBarAsNeeded)
        self._controls_scroll = controls_scroll
        self._controls_stack = QStackedWidget()
        self._controls_stack.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Preferred)
        self._controls_stack.setMinimumWidth(0)
        self._config_panel = self._build_config_panel()
        self._complete_state_panel = self._build_complete_state_panel()
        self._complete_state_panel.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Preferred)
        self._complete_state_panel.setMinimumWidth(0)
        self._controls_stack.addWidget(self._config_panel)
        self._controls_stack.addWidget(self._complete_state_panel)
        self._controls_stack.setCurrentWidget(self._config_panel)
        controls_scroll.setWidget(self._controls_stack)
        controls_scroll.setObjectName("workflowControlsScroll")

        log_group = self._build_log_panel()
        self._log_group = log_group

        layout.addWidget(controls_scroll, 1)
        layout.addWidget(log_group, 0)
        self._sync_live_log_disclosure_layout(
            expanded=bool(
                hasattr(self, "_live_log_disclosure_btn")
                and self._live_log_disclosure_btn.isChecked()
            )
        )
        return pane

    def _refresh_left_column_width_clamp(self) -> None:
        """Refresh geometry so controls track left-pane viewport width after disclosure toggles."""
        controls_scroll = getattr(self, "_controls_scroll", None)
        controls_stack = getattr(self, "_controls_stack", None)
        if controls_scroll is None or controls_stack is None:
            return
        controls_stack.updateGeometry()
        config_panel = getattr(self, "_config_panel", None)
        if config_panel is not None:
            config_panel.updateGeometry()
        controls_scroll.updateGeometry()
        controls_scroll.viewport().updateGeometry()

