    def _on_timeline_anchor_mode_changed(self) -> None:
        """Toggle fixed-anchor time input visibility/enabled state."""
        if not hasattr(self, "_fixed_daily_anchor_time_edit"):
            return
        fixed_mode = self._timeline_anchor_mode_value() == "fixed_daily_anchor"
        phasic_active = is_isosbestic_active(self._mode_combo.currentText())
        plotting_layout = self._plotting_group.layout() if hasattr(self, "_plotting_group") else None
        if isinstance(plotting_layout, QFormLayout):
            fixed_label = plotting_layout.labelForField(self._fixed_daily_anchor_time_edit)
            if fixed_label is not None:
                fixed_label.setVisible(fixed_mode)
        self._fixed_daily_anchor_time_edit.setVisible(fixed_mode)
        self._fixed_daily_anchor_time_edit.setEnabled(bool(fixed_mode and phasic_active))

    def _on_plotting_mode_changed(self) -> None:
        """Map single plotting mode control to legacy per-family render settings."""
        target = "full" if self._plotting_mode_combo.currentText() == "Full" else "qc"
        for attr in (
            "_sig_iso_render_mode_combo",
            "_dff_render_mode_combo",
            "_stacked_render_mode_combo",
        ):
            combo = getattr(self, attr, None)
            if combo is not None and combo.findText(target) >= 0:
                combo.blockSignals(True)
                combo.setCurrentText(target)
                combo.blockSignals(False)

    def _selected_run_profile(self) -> str:
        combo = getattr(self, "_run_profile_combo", None)
        if combo is None:
            return "full"
        data = combo.currentData()
        if data in {"full", "tuning_prep"}:
            return str(data)
        text = combo.currentText().strip().lower()
        return "tuning_prep" if "tuning" in text else "full"

    @staticmethod
    def _run_profile_display_name(run_profile: str) -> str:
        return "Tuning Prep Run" if run_profile == "tuning_prep" else "Full Run"

    def _on_run_profile_changed(self) -> None:
        if not hasattr(self, "_run_profile_note_label"):
            return
        run_profile = self._selected_run_profile()
        if run_profile == "tuning_prep":
            self._run_profile_note_label.setText(
                "Tuning Prep Run contract: guarantees completed-run metadata plus "
                "_analysis/phasic_out/phasic_trace_cache.h5 and config_used.yaml for downstream tuning + correction retune.\n"
                "Stage 2 behavior: intentionally omits tonic cache generation and skips nonessential summaries/day-plots for lighter execution while preserving tuning contracts."
            )
            self._set_status_label_style(self._run_profile_note_label, "info")
        else:
            self._run_profile_note_label.setText(
                "Full Run: complete output package for routine production deliverables."
            )
            self._set_status_label_style(self._run_profile_note_label, "ready")

